INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_43333','Осінні квіти вже зійшли',NULL,'uk','ukr_ssr_1919_1991',NULL,NULL,NULL,NULL,'Осінні квіти вже зійшли
Морозними вітрами,
Як посіпаки нас вели,
Глузуючи над нами.

Приспів:
Ой тямлю, тямлю я той час,  |
Ти плакала за мною,         |
І на прощання раз у раз     | (2)
Махала хустиною.            |

Ой не шалійте вороги,
Бо сміх вуста вам скрутить.
Нас не лякають ланцюги
І дух наш не помутять.

Приспів:
Ой тямлю, тямлю я той час,  |
Коли село горіло.           |
І чути було плач дітей,     | (2)
Матерів серце мліло.        |

А Гонти мстивий дух зове
З уманської різниці.
Він нашу славу підійме
З глибокої в''язниці.

Приспів:
Тоді настане страшний суд,  |
І зацвіте руїна.            |
В огні і крові, в боротьбі  | (2)
Воскресне Україна.          |','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_43333'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_43333','Осінні квіти вже зійшли','Осінні квіти вже зійшли
