INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_433939','Бігла Теличка тай з Бережечка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Стародавні Колядки-Щедрівки: Українські Різдво Світа і Щедрий Вечір. Радуйся Земле Коляда їде! Листки з приводу цієї Пісні: Що означає ім''я "Коляда"? Що означає "Дідух"? Співаймо Світові-Дитині: Колядки, Щедрівки, Колискові... Стежки до листків про Українські традиції.','Бігла Теличка тай з Бережечка
