Я Тобі Дядю заколядую
Дай Пиріг
Не дасиш Пирога
Візьму Вола за Рога
А Кобилу за Чуприну
Тай поведу за Долину
Тай продам за Шажок
І куплю Пиріжок щоб не побіг
На Біленький Сніжок !','["pisni.org.ua", "cat:kolyadky", "cat:shchedrivky", "Колядки", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_433939'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_433939','Бігла Теличка тай з Бережечка','Бігла Теличка тай з Бережечка
