INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_434185','Ходе Ілля на Василя','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Відміни Пасла Маланка Два Качура Роди Боже Жито й Пшеницю. Сіє Xугу Життяную. Приходив Ілля тай до Василя Ходе Ілля на Василя Xодить Ілля на Василя Сійся-родися Жито-Пшениця! Сійся-родися Жито-Пшениця На Щастя на Здоров''я на Новий Рік Місяченьку Мій Братіку! Місяченьку Мій Братіку Помагай Біг! Помагай Біг на Щастя на Здоров''я Сію-вію-посіваю! Сиплю на Вас Жито щоб довго Вам жити Сію вію посіваю Символіка Щедрого Вечера і Василя. Щедрий Вечер, 13-14 січня, зачинається властиво під Новий Рік (7 днів наперед Богоявління — символ Місячний!), т. є. в вечер перед св. Василя. Це особливо улюблене Українське свято: мітичного Василя і Маланки, — є найщирішим шануванням Місяця з його женихальними мотивами (ними переповнені Щедрівки). Тоді мітичну постать Василя мішають часто з мітольоґійно-Місячною постаттю Іллї — Ілії, який є в Українського народу покровителем урожаїв збіжжя, особливо жита (сніп жита, дід Ілля, — в часі жнив, — це постава Місяця). Стежки до інших листків про Українські традиції.','Ходе Ілля на Василя
Ходе Ілля на Василя
Несе Пугу Житяную
Куди махне Жито росте
Вроди Боже Жито-Пшеницю
І Всяку Пашницю
У Полі Ядро
У Домі Добро
У Полі Колосок
А у Домі Пирожок

Здрастуйте з Новим Годом
З Василем!','["pisni.org.ua", "cat:shchedrivky", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_434185'), datetime('now')),datetime('now'));
