Не клади край Вікна щоб ніхто не вкрав
Ковбаса хороша дайте ще і гроші
Ковбаса та гроші то й Різдво хороше
Колядую-колядую','["pisni.org.ua", "cat:kolyadky", "cat:shchedrivky", "Колядки", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_433889'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_433889','Колядую колядую Ковбасу чую','Колядую колядую Ковбасу чую
