INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4349787','Човнику, пливи','Слова: Зоряна Лісевич','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Пісню виконує Соломія Коваль.','Гойда, гойда-да,
