INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4346185','Мир над Україною','Музика: Руслан Квінта Слова: Петро Мага. Виконує: Наталія Валевська','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Я люблю свої мрії,
Повне серце надії,
Наче птах,
Вилітає з грудей.
Зачекалась країна,
Що у серці єдина,
Для красивих
І вільних людей.
Тебе зігріють,
Наче подих весни,
Твої найкращі
На планеті сини!

Приспів:
Вся Земля,             |
Мов скатертиною,       |
Розцвіте серед зими.   |
Буде мир над Україною! |
Буде мир і будем ми!   | (2)

Ти так довго терпіла,
Коли в серце летіли
Гостряки,
Геть холодні сніги!
Та нездатні зламати
Нашу волю крилату
Всі неправди
І всі вороги!
Тебе зігріють,
Наче подих весни,
Твої найкращі
На планеті сини!

Приспів. (3)','["pisni.org.ua", "cat:patriotic", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4346185'), datetime('now')),datetime('now'));
