І Бог здоров''я щастя вам дає!','["pisni.org.ua", "cat:devoted", "Пісні присвячені окремим особам"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4350389'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4350389','Многая Літа Священику!','За несім молитву творю всього світа,
