INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4353434','Богуслав понад Россю','Музика: Тарас Силенко Слова: Микола Щербак. Виконує: Тарас Компаніченко, Володимир Самайда, Тарас Силенко, Валерій Мартишко','uk','ukraine_1991',NULL,'2017','Літопис авторської пісні України №52 (484) 2017 рік.',NULL,'Богуслав понад Россю
І Корсунь в боях стугонять.
Біла Церква гримить -
Москалів блискавицями стріла.
Наш отаман як грім:
У Черкасах сідлає коня,
Над Дніпром пролетить,
У Таращі розпростує крила...

Як вогонь він випалює
Й нищить московську орду,
Мов двосічним мечем
Розбиває червоних бандитів!
У Трипіллі Зелений
Подивиться в мряку густу,
Де в огні клекотить
І вирує розтерзаний Київ...

Заскрегоче зубами, гляне
З болем на рідне село,
Стисне в боки коня і,
Як вихор, шугне в надвечір''я...
Вільна Січ ожила,
І козацтво, як мак, розцвіло, -
Це Зелений у вічність
Веде українське безмір''я!','["pisni.org.ua", "cat:istorychni", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4353434'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4353434','Богуслав понад Россю','Богуслав понад Россю
І Корсунь в боях стугонять.
Біла Церква гримить -
Москалів блискавицями стріла.
Наш отаман як грім:
У Черкасах сідлає коня,
Над Дніпром пролетить,
У Таращі розпростує крила...

Як вогонь він випалює
Й нищить московську орду,
Мов двосічним мечем
Розбиває червоних бандитів!
У Трипіллі Зелений
Подивиться в мряку густу,
Де в огні клекотить
І вирує розтерзаний Київ...

Заскрегоче зубами, гляне
З болем на рідне село,
Стисне в боки коня і,
Як вихор, шугне в надвечір''я...
Вільна Січ ожила,
І козацтво, як мак, розцвіло, -
Це Зелений у вічність
Веде українське безмір''я!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4351287','Фура і артисти','Музика: Арсен Мірзоян, Олександр Положинський Слова: Арсен Мірзоян, Олександр Положинський. Виконує: Арсен Мірзоян, Олександр Положинський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Не приїхали у місто
Фура з хлібом і артисти,
Сталось, ніби ненавмисно,
Як намисто рветься
Й крапле вниз...
І ні хліба, ні видовищ,
І нічого не воротиш,
Всі слідкують, що говориш,
Якщо мовиш, не чіпай коліс.

Приспів:
Не прийшли у місто фура і артисти,
Жовті видання поширюють плітки,
Розіграють драму під ранкову каву,
Співчуваючи належно поміж тим...
А насправді варто зрозуміти правду,
Все, що сталося, лишається без змін,
І в антракті ніби вистачає хліба,
Та на сцену вийде вже не він...

А ти все кликав на каву,
А я усе не заходив,
То не здоров''я, то справи -
Якісь причини знаходив.
Потім довго не вірив,
В житті всіляке буває,
Коли сказали в новинах,
Що тебе більше немає...
І всі розмови, захоплення,
Спільні плани не здійснені,
Печаллю затоплені,
Заспівані піснями,
Дні, колись такі сонячні,
Сумні і потомлені,
Знову муляють боляче
В серці рани оновлені...

Приспів.

Несподівано прозріли всі навкруг,
Всі несподівано прозріли,
І кожен тобі брат і кожен друг,
Кожен тобі брат одразу й кожен друг.
Несподівано та вже як є, вже як є,
Він залишив кожному своє,
Лишив кожному своє...

Приспів.','["pisni.org.ua", "cat:devoted", "Пісні присвячені окремим особам"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4351287'), datetime('now')),datetime('now'));
