INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4354636','Let it snow','Музика: Jule Styne Слова: Оксана Боровець. Виконує: Шпилясті кобзарі','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Подарунки для нас тримає,
До шкарпеток вночі ховає,
Ти ім''я його заспівай:
Миколай! Миколай! Миколай!
Заспівають сніжинки білі
В порцеляновій заметілі,
Стане на наш поріг
Новий Рік! Новий Рік!
Як у небі зоря зійде,
Розпочнуться дива ураз,
Світла радість у дім іде -
Казка настане для нас!
Сяє вулиця ліхтарями,
Усміхнеться дитя до мами,
Нумо разом свято назвемо:
Це Різдво! Це Різдво!
Це Різдво!

Як у небі зоря зійде,
Розпочнуться дива ураз,
Світла радість у дім іде -
Казка настане для нас!
Подарунки для нас тримає,
До шкарпеток вночі ховає,
Ти ім''я його заспівай:
Миколай! Миколай! Миколай!
Пригорни, коли хтось сумує,
Новий Рік Ангела дарує,
Хай любов''ю світ обійма
Ця зима! Ця зима! Ця зима!
Ця зима! Ця зима! Ця зима!
Хай любов''ю нас всіх
Вона з вами обійма!
З Новим Роком!','["pisni.org.ua", "cat:svyatyy-mykolay", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4354636'), datetime('now')),datetime('now'));
