INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_4354636_l1','pisniua_4354636','YouTube','https://www.youtube.com/watch?v=2p-h0KB9sPc','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4354939','Останній дзвоник','Музика: Ірина Лончина Слова: Ірина Лончина. Виконує: Ірина Лончина','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ось і закінчився рік,
Зі школою прощаємось ми...
Чом же найкращі шкільні
Дні відлітають у сни..
Згадуєм перший урок,
Мудрі поради й слова,
Що відкривали нам світ,
Вели у простір життя.

Приспів:
Школо моя, ти прощавай,
Не забувай, як перший раз
Ми увійшли в цей клас...
Школо моя, вчителю мій,
Ти пригадай радість і сум
Допитливих цих очей...

Плаче останній дзвінок,
Бо не покличе вже нас
На незабутній урок
В сонячний радісний клас...
Сумно зітхає верба,
Поруч батьки, вчителі,
Серце щемить, а в душі
Ми ще, як ті школярі...

Приспів.

Сльози блищать на очах,
Як нас хвилюють слова,
Бо усвідомлюємо ми,
Що вже прощатись пора...
Доля заплутає нас
У лабіринтах життя,
Але ми вірим у те,
Що світле у нас майбуття!

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4354939'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4354939','Останній дзвоник','Ось і закінчився рік,
