INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4351539','Ялиночка','Українська народна пісня. Виконує: Алла Мігай','uk','ukraine_before_1917',NULL,NULL,'http://minus.lviv.ua/minus/artist/%D0%9D%D0%B5%D0%B2%D1%96%D0%B4%D 0%BE%D0%BC%D0%B8%D0%B9%20%D0%B2%D0',NULL,'Ялиночка!.. Ялиночка!..

Жила собі ялиночка
Уу тихому ліску,
Зозуля на ялиночці
Співала нам "ку-ку"
І білочка-пустуночка
Гойдала гілочки,
Щоранку до ялиночки
Зліталися пташки.

Приспів:
Ялиночка, ялиночка      |
У гості знов прийшла    |
Ялиночка, ялиночка      |
Нам радість принесла!.. | (2)

Зустріли ми ялиночку,
Як гостю дорогу
І дощиком-веселиком
Прикрасили усю,
Повісили ліхтарики,
Дзвіночки чарівні
Чи добре тобі з нами,
Ялиночка, чи ні?

Приспів. (2)','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4351539'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4351539','Ялиночка','Ялиночка!.. Ялиночка!..

