INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4371931','Колискова','Українська народна пісня. Виконує: Тетяна Горобець','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Мала Катерина
Два маленьких сина.
Разом породила
Гриця та Данила.
Сім літ доглядала,
Любистком вмивала,
Долі їм благала,
Колисаночки співала:
Люлі-люлі-люлечки,
Шовковії вірвечки.
Мальовані бильця
Для Данилка і Гриця.

Хмари йшли за обрій,
Йшли часи недобрі
Й недобрії вісті:
Не стало що їсти.
Свої, не чужії,
Вороженьки лишити
Могли козачаті...
Все до крихти -
Геть із хати.
Ляжте, діти, спати,
Бо нема чим годувати.
Ой, люлі-люлі,
Налетіли гулі.
Стали думать і гадать,
Чим синочків годувать.
Чи яблучком, чи медком,
Чи солодким пиріжком.

...Мов ворожа сила,
Півсела скосила.
Сусідська родина
В одній домовині...
Кругом людське горе
Розлилось, як море,
Не минуло, кляте,
Катриної хати.
Бо ще й не світало,
Як Гриця не стало...
Одкувало в хаті -
Не ходи по хаті.
Ой, котику, не гуди -
Спить дитина, не буди.

...З останньої сили
Води наносила.
Води наносила,
В печі натопила.
Кликала Данильця:
Вставай, сину,
Їсти Гриця!..
Не озвавсь Данилко,
Вже й не озоветься.
Впала Катерина,
Вже не підведеться...
...Люлі-люлі-люлечки,
Шовковії вірвечки.
Мальовані бильця
Для Данилка і Гриця...','["pisni.org.ua", "cat:istorychni", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4371931'), datetime('now')),datetime('now'));
