INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4392083','Різдво','Музика: Тетяна Навроцька (Tanya Navrotski) Слова: Марія Звірід (Mariya Zvirid)','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Пісню виконує Христина Банар (Kristy Banar).','В ніч цю прекрасну Спаситель прийшов
І людям нещасним приніс Він любов,
І ангели радість звіщали землі
Дарунок небесний дитині малій!
Ягнятка дрімали і пахло теплом,
Марія гойдала синочка свого.
А стомлене місто, огорнене сном,
І сяяла зорі яскраві віком!

Приспів:
Різдво - це радість!       |
Різдво - це щастя!         |
Це Божа милість і доброта! |
Це мир і правда!           |
Це неба частка!            |
Любов безмежна і чистота!  | (2)

Схиляю коліна і серце своє,
Я думкою лину в те місце святе!
Я дякую, Боже, за дивне Різдво,
Що мир і спасіння всім нас принесло!

Приспів.','["pisni.org.ua", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4392083'), datetime('now')),datetime('now'));
