INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_439287','Світить Місяць у Раю Нашому Короваю','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,'Весільні — Свята Неділя: Поділ Короваю. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Еротика, жарти, забави, загадки: Катерини – Калета – Андрія... Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... Мед і Ябка... Рай розвився Господь звеселився. Старший Дружко Коровгай крає Щоб було видненько покраять Його дрібненько. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Жертви для Бога як реліґійний ідеал. Свята, Тайна, Вечеря 6.01 — Що вона означає і як її підготувати? Св. Микола 19.12 – Народний речник перед Богом і Прадід. Бог, Різдво Світа, Дідух і Лицарі. Коляда і Великдень: Різдво і Відродження Світа. Про Свято Івана Купала Весілля — Свята Неділя: Святий Коровай. Стежки до листків про Українські традиції. Прислів''я: На чужий коровай очей не поривай да собі дбай.','Світить Місяць у Раю Нашому Короваю
Щоб було видненько покраять Його дрібненько','["pisni.org.ua", "cat:vesilni", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_439287'), datetime('now')),datetime('now'));
