INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_439736','Темненькая нічка','Музика: о. Й. Фацієвич Слова: о. Й. Фацієвич. Виконує: Лебеді кохання','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Темненькая нічка світ закрила,        | (2)
На небеснім полі зорі запалила.

Одна лиш зіронька понад усі сяє       | (2)
Та над Вифлеємом сяйво розливає.

А во Вифлеємі нині мир з''явився,      | (2)
Люди веселіться, сам Бог народився.

Народився нині з Марії-Дівиці,        | (2)
З Пречистої славної тай Богородиці.

Вчули вів чароньки голос той із неба  | (2)
Зібрались на раду, куди їм йти треба.

Пішли вони шляхом тою дорогою         | (2)
Куди ясність слалась, за тою звіздою.

І ми підім з ними, поклін Йому даймо  | (2)
Та радісну пісню всі враз заспіваймо','["pisni.org.ua", "cat:cerkovni", "cat:christian", "cat:kolyadky", "Церковні пісні", "Пісні на християнську тематику", "Колядки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_439736'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_439736','Темненькая нічка','Темненькая нічка світ закрила,        | (2)
