INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4394232','Пісня для батьків','Музика: Володимир Будейчук Слова: Ірина Зінковська','uk','ukraine_1991',NULL,NULL,'https://youtu.be/YedGBXF9xhc','На каналі ще багато цікавих мінусовок. Підписуємось та співаємо. Пісню виконують Наталія і Сніжана Сідлярчуки. Мінус на каналі: https://youtu.be/YedGBXF9xhc.','Де мама там любов і ніжна ласка,
Де тато там добро і майбуття,
Мені даруєте ви справжню казку,
З якою йду в незвідане життя.
Любистком росах встелені дороги,
Барвінком зазоріли всі поля,
Я - втіха татка, мамі допомога,
Як доня віддано люблю вас я!

Приспів:
Мамо, матусю, ти найкраща і єдина,    |
Мій таточку, ти найдорожчий на землі! |
Я вдячна Богу, що міцна родина,       |
Щоднини щастя ви даруєте мені!        | (2)

Безсонні ночі провела матуся,
Щасливо долю доні берегла,
Ви завжди поруч, я до вас горнуся,
У вашої любові два крила!
Любистком росах встелені дороги,
Барвінком зазоріли всі поля,
Я - втіха татка, мамі допомога,
Як доня люблю віддано вас я!

Приспів.','["pisni.org.ua", "cat:pro-batkiv", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4394232'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4394232','Пісня для батьків','Де мама там любов і ніжна ласка,
Де тато там добро і майбуття,
Мені даруєте ви справжню казку,
З якою йду в незвідане життя.
Любистком росах встелені дороги,
Барвінком зазоріли всі поля,
Я - втіха татка, мамі допомога,
Як доня віддано люблю вас я!

Приспів:
Мамо, матусю, ти найкраща і єдина,    |
Мій таточку, ти найдорожчий на землі! |
Я вдячна Богу, що міцна родина,       |
Щоднини щастя ви даруєте мені!        | (2)

Безсонні ночі провела матуся,
Щасливо долю доні берегла,
Ви завжди поруч, я до вас горнуся,
У вашої любові два крила!
Любистком росах встелені дороги,
Барвінком зазоріли всі поля,
Я - втіха татка, мамі допомога,
Як доня люблю віддано вас я!

Приспів.');
