INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4397787','Вітай, Богородице',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Вітай, Богородице,
Радуйся, миру Царице,
Ти зродила свого Творця,
Теотокос навіки Діва!

Син Єдинородний в лоні Отця
Народжений, Слово Божества,
Як настала часу повнота
Став одним з нас,
Ввійшла вічність в час,
Мир для всіх нас!

Приспів.

Син Діви Марії - Слово Отця
Повноту взяв людського єства.
Його Мати виховувала -
Радість дала, любов зберегла,
Мир принесла!

Приспів.

Учениця Сина в школі Отця,
Вдячна Діва Ним відкуплена,
Святим Духом вся отінена,
Для нас дана, Вона - Пресвята,
Мир зберегла!

Приспів.','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4397787'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4397787','Вітай, Богородице','Приспів:
Вітай, Богородице,
Радуйся, миру Царице,
Ти зродила свого Творця,
Теотокос навіки Діва!

Син Єдинородний в лоні Отця
Народжений, Слово Божества,
Як настала часу повнота
Став одним з нас,
Ввійшла вічність в час,
Мир для всіх нас!

Приспів.

Син Діви Марії - Слово Отця
Повноту взяв людського єства.
Його Мати виховувала -
Радість дала, любов зберегла,
Мир принесла!

Приспів.

Учениця Сина в школі Отця,
Вдячна Діва Ним відкуплена,
