INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4397436','Машинки','Музика: Олександр Шевченко Слова: Олександр Шевченко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ми хочемо діткам усім
Розповісти
Для чого машинки
Між нами живуть,
Як працюють ті машинки,
Мають добре ремесло,
Помагають вони людям,
Щоби легше їм було.

Приспів:
Їдуть, їдуть на роботу,
Вирушають зранку в путь!
Їдуть, їдуть, їдуть, їдуть,
Лиш моторчики гудуть!

Пожежна машинка -
Яскраво-червона,
Завжди поспішає,
Завжди поспіша,
І працює, і чергує
Від темна і дотемна,
Щоб хатинки не горіли,
Порятує їх вона!

Приспів.

Швидка допомога,
Така необхідна,
Біленька машинка
З червоним хрестом,
І працює, і чергує
Від темна і дотемна,
Щоби люди не хворіли,
Захищає їх вона!

Приспів.

Щоб був на дорогах
Порядок і спокій,
Машинка поліції
Їде туди,
І працює, і чергує
Від темна і дотемна,
Щоб машинки не сварились,
Примиряє їх вона!

Приспів.

Машинка маршрутка -
Автобус маленький -
Куди нам потрібно,
Туди й довезе!
Їздить, їздить
Та маршрутка,
Їздить зранку до темна,
Щоб ми пішки не ходили
Порозвозить нас вона!

Приспів.

Машинка таксі
Куди схочеш - приїде,
Тоді, куди схочеш -
Тебе відвезе!
Їздить, їздить і працює
Від темна і до темна,
Якщо дуже поспішаєм -
Допоможе нам вона!

Приспів.

А ось - вантажівка,
Машина вантажна,
Вона дуже сильна,
Сильніша за всіх!
І працює, і працює
Від темна і до темна
Щоб важке ми не носили,
Вантажі везе вона!

Приспів.

Зламалась машинка,
Або заблудилась,
Евакуатор підвозить її!
Він працює і працює,
Він рятує у біді,
Як потрібна допомога -
Приїжджає він тоді!

Приспів.','["pisni.org.ua", "cat:dytyachi", "Дитячі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4397436'), datetime('now')),datetime('now'));
