INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_4397436_l1','pisniua_4397436','YouTube','https://www.youtube.com/watch?v=ztMP8RU_E00','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4397838','Діво найсвятіша',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Діво найсвятіша, хто тебе звеличить
За ті дивні речі, що пізнав Бердичів!
Пресвята Маріє з Немовлям чудесним,
Без гріха зачата Лілея небесна.

Бідні і багаті, королі й каліки -
Всі себе ввіряють під Твою опіку,
В Тобі їх надія, о, Мати єдина,
Ублагай ласкаво за них свого Сина.

В них у кожнім домі Образ Твій святий є,
Пред яким в пошані все благоговіє,
Хай на віки вічні слава Твоя буде,
"Радуйся, Маріє!" - хай співають люди.

Ясні, як від сонця і зірок на небі,
Ми, Царице, грішні горнемось до Тебе.
Скарбе найдорожчий, даний Божим дітям,
В світі християнськім славою повитий.

Ти, ласкава Діво, борониш від злого -
В кожній справі молиш за нас Бога,
Тож із щирим серцем до Тебе взиваєм,
Вислухай, покірно, ми Тебе благаєм.','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4397838'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4397838','Діво найсвятіша','Діво найсвятіша, хто тебе звеличить
За ті дивні речі, що пізнав Бердичів!
Пресвята Маріє з Немовлям чудесним,
Без гріха зачата Лілея небесна.

Бідні і багаті, королі й каліки -
Всі себе ввіряють під Твою опіку,
В Тобі їх надія, о, Мати єдина,
Ублагай ласкаво за них свого Сина.

В них у кожнім домі Образ Твій святий є,
Пред яким в пошані все благоговіє,
Хай на віки вічні слава Твоя буде,
"Радуйся, Маріє!" - хай співають люди.

Ясні, як від сонця і зірок на небі,
Ми, Царице, грішні горнемось до Тебе.
Скарбе найдорожчий, даний Божим дітям,
В світі християнськім славою повитий.

Ти, ласкава Діво, борониш від злого -
В кожній справі молиш за нас Бога,
Тож із щирим серцем до Тебе взиваєм,
Вислухай, покірно, ми Тебе благаєм.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4398083','Мати невтомної допомоги',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Мати невтомної допомоги
Вислухай в небі голос душі
Грішної й благаючої про допомогу.

Мати невтомної допомоги,
Прошу, щоб кожний у своїй долі
Прийняв в покорі Хрест Божої волі.

Мати невтомної допомоги,
В кожній потребі порятуй в біді
Мою душу слабку, Царице в небі.

Мати невтомної допомоги,
Посеред болю та випробування
Дай нам з любов''ю
Прийняти страждання.

Мати невтомної допомоги,
Коли вже прийде смерті година,
Заведи мене в Царство свого Сина!','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4398083'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4398083','Мати невтомної допомоги','Мати невтомної допомоги
Вислухай в небі голос душі
Грішної й благаючої про допомогу.

