INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4398131','Матінко кохана',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Гавриїл звістив Їй, що народить Сина.
Так - відповідала ангелу Марія.
За діянням Духа з неба високого
Бог зіслав на землю Сина для нас свого.

Приспів:
Матінко кохана, Матінко ласкава,
Діво над дівами, молися за нами.
Матінко Христова, Матінко чудова,
Діво над дівами, молися за нами.

Приспів.

Ти терпів, Ісусе, зносив тяжкі муки:
Хрест, пробите серце, розіп''яті руки.
Коли за гріх світу небо помирало,
Серденько Марії під хрестом страждало.

Приспів.

Вічне Алілуя! Син Твій воскресає!
В славу неба входить, наче сонце сяє.
Дух Святий провадить у небесні двори,
Там Йому співають Ангельські хори.

Приспів.','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4398131'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4398131','Матінко кохана','Гавриїл звістив Їй, що народить Сина.
