INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_439583','Хата моя, біла хата','Музика: Анатолій Пашкевич Слова: Дмитро Луценко. Виконує: Раїса Кириченко','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Хата моя, біла хата,
Рідна моя сторона.
Пахне любисток і м''ята,
Мальви цвітуть край вікна.

Хата моя, біла хата,
Казко тепла й доброти.
Стежка від тебе хрещата
В''ється в далекі світи.

В хаті спокійно й затишно,
Вечір десь бродить в гаю.
Мати задумливо й ніжно
Гладить голівку мою.

Мамо, чого зажурились?
Дайте тепла ваших рук.
В хаті на згадку лишились
Болі й тривоги розлук.

Хата моя, біла хата,
В білому світі одна.
Пахне любисток і м''ята,
Мальви цвітуть край вікна.

В''ється дорога далека
В хату крізь синю рапчу.
Мамо, до вас, як лелека,
В горі і щасті лечу','["pisni.org.ua", "cat:krasa-pryrody", "cat:nostalgia", "cat:patriotic", "cat:pro-batkiv", "Пісні про красу природи", "Пісні з ностальгічними мотивами", "Патріотичні пісні", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_439583'), datetime('now')),datetime('now'));
