INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_439583_l1','pisniua_439583','YouTube','https://www.youtube.com/watch?v=nKfQnymmgv8','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4397930','Маріє',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Навчи мене, Маріє, як слухати Ісуса.
Навчи мене, Маріє, Йому сказати "Так!"
Скажи мені, Маріє, що є життя у Дусі,
Провадь мене, Маріє, до Господа Царя!

Приспів:
Я величальну пісню Господу співаю,
З Тобою, Мамо, я люблю Христа!
Маріє, Діво, благословенна Ти віками,
Свята Царице, неба вічного зоря!

Навчи мене, Маріє, служити у любові,
Нехай завжди у мені панує доброта,
Навчи мене, Маріє, як жити у покорі,
Щоби завжди і всюди я бачила Христа!

Приспів.','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4397930'), datetime('now')),datetime('now'));
