INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4397735','Вислухай нас, Матір Божа',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Вислухай нас, Матір Божа,
Пісні Тобі ми співаєм.
Руки свої піднесемо,
З болем до Тебе взиваєм.

Приспів:
У вівтаря на колінах,
Свої серця віддаємо,
Пожертвував душу до Тебе,
Ми чисті серцем прийдемо,
Світу чудовная мати.

В біді заспокой наше серце,
Від слабостей наших ізбав,
Силою нам буде віра,
Холодний світ зігрівай.

Приспів.','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4397735'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4397735','Вислухай нас, Матір Божа','Вислухай нас, Матір Божа,
