INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4398236','Кров Христа свята',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Кров найдорожча,
Кров Христа свята,
Напій життя,
Небом для нас даний,
Криниця ласки
Нашого спасіння,
Ти лікуєш серця рани.

В келиху Божім
Від людей закрита,
Аби життям нас
Вічним напувати.
Тебе ми просимо,
Щоб Господь-Спаситель
Милосердя міг нам дати.

Кров найдорожча,
Кров свята, пречиста,
Що джерело
У серці Спаса мала,
Честь і подяку
Ми Тобі складаємо.
Слава Тобі, Кров, слава!','["pisni.org.ua", "cat:strasni", "Страсні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4398236'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4398236','Кров Христа свята','Кров найдорожча,
Кров Христа свята,
Напій життя,
