INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_439838','Доня моя, донечка','Музика: Микола Свидюк Слова: Олексій Кононенко. Виконує: Микола Свидюк','uk','ukraine_1991',NULL,NULL,'Український формат Випуск1 /2002',NULL,'Моє сонце, моє небо, моя доня,
Моя радість, моя втіха, моя доля.
Зусрічають тата крильця-рученята,
Зорі-оченята,  оченята-зорі,
І немає на землі   ні біди, ні горя,  | (2)

Приспів:
Дівчинка-перлинка,    |
Золота краплинка,     |
Весняна росинка,      | (2)
Літнє моє сонечко,    |
Доня моя, донечка.  |

Мої мрії, мої весни, моя доня,
Мої думи, мої болі, моя доля.
Світом-пересвітом від зими до літа
Виростають діти, діти виростають,
А над ними в небесах янголи літають. | (2)

Приспів.

Моє щастя, моє серце, моя доня,
Моя лада, моя леля, моя доля.
Казку вечорову, пісню колискову
Пригадаю знову, знову пригадаю
І тобі, моя дитино, знову заспіваю.  | (2)

Приспів.','["pisni.org.ua", "cat:dytyachi", "cat:pro-ditey", "Дитячі пісні", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_439838'), datetime('now')),datetime('now'));
