INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_439939','Казав мені батько','(Щоб я оженився...). Українська народна пісня. Виконує: Медобори','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Казав мені батько,
Щоб я оженився,
По досвітках не ходив    |
Та й не волочився.       | (2)

А я козак добрий
Та й не волочуся,
Де дівчину чую,
Там нічку ночую,
А де молодички,
Там я і дві нічки.

Покіль не женився,
Потіль не журився
Ні ложкою, ні мискою,    |
Ні третьою колискою.     | (2)

А як оженився,
Так і зажурився
І ложкою, і мискою,      |
Ще й третьою колискою.   | (2)

Як прийшов у хату,
Одно каже: "Тату!"
Друге каже: "Папи!" [мелодія 2 такту]
Жінка каже: "Бери шапку, |
Тікай к чорту з хати.    | (2)

Тікай к чорту з хати
У поле орати,
А я собі, молоденька,    |
Піду погуляти".          | (2)','["pisni.org.ua", "cat:zhartivlyvi", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_439939'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_439939','Казав мені батько','Казав мені батько,
Щоб я оженився,
По досвітках не ходив    |
Та й не волочився.       | (2)

А я козак добрий
Та й не волочуся,
Де дівчину чую,
Там нічку ночую,
А де молодички,
Там я і дві нічки.

Покіль не женився,
Потіль не журився
Ні ложкою, ні мискою,    |
Ні третьою колискою.     | (2)

А як оженився,
Так і зажурився
І ложкою, і мискою,      |
Ще й третьою колискою.   | (2)

Як прийшов у хату,
Одно каже: "Тату!"
Друге каже: "Папи!" [мелодія 2 такту]
Жінка каже: "Бери шапку, |
Тікай к чорту з хати.    | (2)

Тікай к чорту з хати
У поле орати,
А я собі, молоденька,    |
Піду погуляти".          | (2)');
