INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4398838','Діво Пресвята у зоряній короні','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Пісню виконує гурт Sursum Corda.','Діво Пресвята у зоряній короні,
В сонячній оздобі Ти сяєш, мов зоря,
Місяць під стопою, царюєш в небесах,
Обіцяну нам Богом надію принесла!

Мати Пресвята, всіх грішників надія,
Просимо Тебе, молися ти за нас!
Сину Твоєму наш цілий світ радіє,
Бо Твій любий Син - наш вічний Бог і Спас!

Залишаючись вірна у підніжжя хреста,
Розділяла Сама з Ісусом Його біль.
Тебе, Мати спасіння прославляє земля,
Бо та Кров''ю Христа відкуплена з гріха!..

Непорочная Діво, що не знала гріха,
Взята на небеса, царюєш з Сином.
Ти, о, небесна Царице, заступайся за нас,
Щоби нашим життям прославився Твій Син!..

Понад ангельські хори в Царство Сина Твого,
Коли час надійшов, вознесена була,
Як радіє Тобою цілий Божий народ
Бо явив нам Господь у Тобі знак життя.','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4398838'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4398838','Діво Пресвята у зоряній короні','Діво Пресвята у зоряній короні,
