INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4399134','Гімн дітей України','Музика: Михайло Вербицький Слова: Павло Чубинський','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Little Blues.','Процвітає Україна її слава й воля!
Вже нам, браття українці, усміхнулась доля!
Гинуть наші вороженьки, як роса на сонці,
Бо пануємо ми, браття, у своїй сторонці!
Душу й тіло ми зміцнили за нашу свободу,
Бо віками ми є браття козацького роду!

Чорне море нам сміється, Дід Дніпро радіє,
Бо у нашій Україні доленька квітніє!
А завзята праця щира всіх нас об''єднає,
Пісня волі в Україні гучніше лунає!
Душу й тіло ми зміцнили за нашу свободу,
Бо віками ми є браття козацького роду!

Процвітає Україна її слава й воля!
Вже нам, браття українці, усміхнулась доля!
Гинуть наші вороженьки, як роса на сонці,
Бо пануємо ми, браття, у своїй сторонці!
Душу й тіло ми зміцнили за нашу свободу,
Бо віками ми є браття козацького роду!
Козацького роду!','["pisni.org.ua", "cat:patriotic", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4399134'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4399134','Гімн дітей України','Процвітає Україна її слава й воля!
