INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_4399134_l1','pisniua_4399134','YouTube','https://www.youtube.com/watch?v=oIEDRHEJl5U','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4398532','О, Пресвятая Діво Маріє',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'О, Пресвятая Діво Маріє,
Наш кожен подих до Тебе лине.
Почуй прохання, всіх нас помилуй,
Зміцни в нас віру, Пречиста Діво!

Земні й небесні хори співають,
Шану, Маріє, Тобі складають:
Мов серед квітів лілія біла,
Мов зірка в небі - Пречиста Діва!

Ти, що Спасіння в лоні носила,
Вкажи дорогу до свого Сина,
Дай нам поживу, зішли надію,
Врятуй від бід нас, Пречиста Діво!

Ти, що страждання з Сином ділила
І хрест сльозами болю скропила,
Мати, веди нас до воскресіння,
Спаси від смерті, Пречиста Діво!','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4398532'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4398532','О, Пресвятая Діво Маріє','О, Пресвятая Діво Маріє,
Наш кожен подих до Тебе лине.
Почуй прохання, всіх нас помилуй,
