INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4400535','Вже Христос із мертвих встав',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Вже Христос із мертвих встав,
Добрий приклад нам подав.
Ми із мертвих теж повстанем,
З Ним у Царстві жити станем!
Алілуя!

В гробі Він лежав три дні,
Дав пробити бік собі
І прийняв тяжкі страждання
Ради нашого спасіння!
Алілуя!

До Ісуса діви йшли,
Мазі дорогі несли -
Тіло Спаса натирати,
Хвалу й честь Йому віддати!
Алілуя!

Як до гробу прибули,
Враз з''явився Ангел білий:
Не лякайтесь, діви милі,
Вже Христа нема в могилі!
Алілуя!

Він воскрес! Христос живий!
Ось і гріб Його пустий.
Нині вранці домовину
Божий Син навік покинув!
Алілуя!

Все, чого ми так бажали,
Ми сьогодні дочекались.
Будьмо нині всі веселі
І радіймо, як Ангели!
Алілуя!','["pisni.org.ua", "cat:voskresni", "Воскресні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4400535'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4400535','Вже Христос із мертвих встав','Вже Христос із мертвих встав,
