INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4389034','Ой, з-за гори туман налягає','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Демуцький П. Українські народні пісні. − Київ: Мистецтво, 1954.','Ой, з-за гори туман налягає,
Гей, ой, з-за гори туман налягає,
За туманом нічого не видно.

Тільки видно в степу криниченьку,
Гей, тільки видно в степу криниченьку,
Там холодна, ой, да водиченька.

Ой, там улан коня напуває,
Гей, ой, там улан коня напуває,
А дівчина води підливає.

Ой, поїдьмо, дівчинонько, з нами,
Гей, ой, поїдьмо, дівчинонько, з нами,
З молодими, ой, да уланами!

Вийшла мати за нову комору,
Гей, вийшла мати за нову комору −
Нема дочки, нема й поговору.

Ввійшла мати знадвору до хати,
Гей, ввійшла мати знадвору до хати,
Стала своїх синів пробуджати.

Сини мої, сини дорогії,
Гей, сини мої, сини дорогії,
Та й сідлайте коні воронії.

Поганяйте битими шляхами,
Гей, поганяйте битими шляхами,
Доганяйте сестру з уланами!','["pisni.org.ua", "cat:naddnipryanski", "Наддніпрянські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4389034'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4389034','Ой, з-за гори туман налягає','Ой, з-за гори туман налягає,
