INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4400436','Скиньте траур',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Скиньте траур, хто в жалобі
По Христу розп''ятому,
Заспіваймо пісню слави
І вклонімося Йому!
Нині добра є новина:
Встав Христос із домовини.
Алілуя! Алілуя!
Хай лунає "Алілуя!"

Стали свідками Ангели
Незабутніх тих хвилин:
Камінь з гробу відвалився -
І воскрес із мертвих Він.
Спаса нашого вітаймо,
Йому честь і шану даймо!
Алілуя! Алілуя!
Хай лунає "Алілуя!"

Дню Господнього спасіння
Раді люди на землі,
Бо воскрес Він після смерті,
Весь у сяйві і хвалі!
Всі серця, що сумували,
Славу Богу заспівали:
Алілуя! Алілуя!
Хай лунає "Алілуя!"','["pisni.org.ua", "cat:voskresni", "Воскресні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4400436'), datetime('now')),datetime('now'));
