INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4385787','В Києві осінь...','Музика: Борис Таршис Слова: Наталя Могилевська, Сергій Підкаура. Виконує: Наталя Могилевська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Осінь... Осінь... Осінь... Осінь...

Осінь з''явилась така несподівана,
В місто каштанове знову прийшла вона
І цілий день холодний дощ пливе по вікнах.
Злива гуляє по вітряних вулицях,
Злива, якої, здається, нема кінця,
Ти думаєш про те, до чого так не звикли...
Я стою одна, і ти один біля вікна
Будеш сумувать про дотики тепла...
Тіні на стіні... Може так, а може ні
В ці холодні дні...

А в Києві осінь... Осінь... |
А в Києві осінь... Осінь... | (2)

Осінь з''явилася така несподівана,
Місто каштанове плаче розірване,
Ми біжимо від себе і куди не знаєм...
Злива іде одиноко по вулиці,
Злива торкається тихо твого лиця,
Хто скаже про любов, якої більш немає?...

А в Києві осінь... Осінь... |
А в Києві осінь... Осінь... | (2)','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4385787'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4385787','В Києві осінь...','Осінь... Осінь... Осінь... Осінь...

