INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_440481','Місто моє','(Місто, премісто). Музика: Зоя Слободян Слова: Ліна Костенко. Виконує: Зоя Слободян','uk','ukraine_1991',NULL,NULL,'Аудіо-CD "Зоя Слободян. Давай помовчимо (співана поезія)" (2000)','Текст записано на слух з аудіо.','Передмова:
Буває мить якогось потрясіння:
Побачиш світ, як вперше у житті.
Звичайна хмарка, сіра і осіння,
Пропише раптом барви золоті...

Місто, премісто, прамісто моє!
Стійбище людське з асфальту й бетону.
Як там не буде, а все-таки є
той силует у вікні золотому!

Ось я проходжу, і ось я пройду.
Може, й навік, але справа не в тому -
тільки б не танув, як тінь на льоду,
той силует у вікні золотому!

Скільки душа прориває тенет
з моря і суші додому, додому.
Там, де у мене є той силует,
той силует у вікні золотому','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_440481'), datetime('now')),datetime('now'));
