INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4400032','Радуйся, Пані світу',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Радуйся, Пані світу,
Небесна Царице,
О, Діво дів преславна,
Досвітня Зірнице!

Радуйся Благодатна,
Ясне світло Боже,
Хай милість Твоя, Пані,
Світ слабкий споможе.

Єдинородному Слову
Наш Господь одвіку
Тебе обрав за Матір,
Матір сонцелику.

Він Ним і землю, і море,
Й небо променисте,
Повітря свіже, й води
Сотворив пречисті.

Як славну Наречену
Оздобив для cебе,
І перший гріх Адама
Не торкнувся Тебе.','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4400032'), datetime('now')),datetime('now'));
