INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4400838','Не зостанусь я!','Музика: Едуард Драч Слова: Едуард Драч','uk','ukraine_1991',NULL,'2020','Літопис авторської пісні України №13 (603) 2020 рік.',NULL,'Не зостанусь я, земляче,
Нині на чужині!
Бо за мною жінка плаче
Десь на Україні...

Плаче, недоцілована,
Ще й дитя голосить,
Нивка недоораная
Хазяїна просить!

Ой, не дбав же ж я ту землю -
Кепський був хазяїн...
Тому в краях чужинецьких
Вештаюсь, як Каїн!..

А душею й тілом лину,
Як в вирій лелека,
Й полечу на Батьківщину
З ситого далека!

Не зостанусь я, земляче,
Нині на чужині!','["pisni.org.ua", "cat:emigration", "Пісні про еміґрацію"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4400838'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4400838','Не зостанусь я!','Не зостанусь я, земляче,
