INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4399939','Хвиля співу нескінченна',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Хвиля співу нескінченна
В небо райдужне зліта.
Це в Твою честь всі співають,
О, Маріє Пресвята!

Приспів:
Ти - святіша від Ангелів,
Дивне чудо із чудес,
Хай Тобі довіку лине
Наша пісня до небес!

О, Царице, Мати Божа,
Ми Тобою лиш живем.
Завдяки Твоїй опіці,
Ми до неба увійдем.

Приспів.

Дай любов Твою і ласку
Всім знедоленим в житті.
Вдячні ми Тобі, Маріє,
За Твої дари святі!

Приспів.','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4399939'), datetime('now')),datetime('now'));
