INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4409338','Голгофа. Хрест',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Голгофа. Хрест. Страшні криваві сни.
Товпа реве: Розпни, розпни, розпни!
І розп''яли, на голові вінок,
По каплі кров спливає з колючок.

Товпа реве: Якщо ти Бог єси,
Зійди з хреста і сам себе спаси!
Якщо ж не Бог, а лиш юдейський цар,
То військами на ворогів удар.

А ти мовчиш, здригаєшся, мов трус,
А ти не Бог, лиш Назорей Ісус.
Голгофа. Хрест. Страшні криваві сни.
Прости їм, Боже, бо сліпі вони.','["pisni.org.ua", "cat:strasni", "Страсні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4409338'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4409338','Голгофа. Хрест','Голгофа. Хрест. Страшні криваві сни.
