INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4408838','Рідна школо','Музика: Юрій Васильківський Слова: Володимир Путята. Виконує: Алла Кудлай','uk','ukraine_1991',NULL,NULL,'авторське подання','Аранжування - Юрій Васильківський, запис - Master Vox Records.','Я прийшла до землі, де зростали малі,
В майбуття нас манила дорога.
Де поради давали як жить вчителі,
Вони - люди від сонця і Бога!
Є у світі земля, їй вклоняюся я,
Що до болю і радості мила!
Ми зростали тоді, як єдина сім''я,
Школа нас із добром жити вчила!

Приспів:
Рідна школа моя, ти - світлиця знання.
Дорога нам, як батько і мати!
Здобували зання ми роками щодня,
Для життя, щоб мудрішими стати!

Я прийшла до землі, у моєму селі,
Пізнавати цей світ вчила школа!
Ті найкращі літа в долі, мов журавлі,
Відлітали у вирій довкола...
Є у світі земля, їй вклоняюся я,
Що до болю і радості мила!
Ми зростали тоді, як єдина сім''я,
Школа нас із добром жити вчила!

Приспів','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4408838'), datetime('now')),datetime('now'));
