INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4413131','Це Різдво!','Музика: Роман Дуда Слова: Роман Дуда. Виконує: Віра Кекелія','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Малює зима пензлем у вікні,
Попід ліхтарями танцює сніг,
Маленька, немов знову вісім мені,
Милуюся, хоч й падаю з ніг!

Приспів:
Це Різдво! Це Різдво! |
Це Різдво! Це Різдво! |
Це Різдво! Це Різдво! |
Це Різдво! Це Різдво! | (2)

Заплющую очі, бачу уві сні
Знов разом, гостей повнісінький дім!
Та чую, як діти співають пісні,
Я бажаю тої радості всім!

Приспів.

Що саме Санта подарує на Різдво мені -
Яскравий светр, чи шматок вугілля?
Гілля вічнозеленої, вбране святково,
Немов чекає шаленої ночі так охоче!

Приспів.','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4413131'), datetime('now')),datetime('now'));
