INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4411736','Мої друзі','Музика: Олег Саліванов Слова: Дмитро Хома','uk','ukraine_1991',NULL,NULL,'авторське подання','Пісню виконує Сузір''я артистів.','Де б не бував, в світах,
Чи в ріднім краю,
Тернистих скільки б не пройшов доріг,
Ніколи друзів я не забуваю,
Чекаю вас завжди на свій поріг!

Приспів:
Стрімка вода гойдає береги,
Пливуть за обрій почуття іллюзій
Та найдорожчими на всі роки
Зостануться у світі мої друзі!

Згадаймо все із вечора до ранку,
Бажання загадають нам зірки,
Залишимо у серці наостанку
Ми тільки щиру дружбу на віки!

Приспів.

Нехай летять у синю даль лелеки,
Нехай життя, то радощі й жалі
І тільки друзі близькі і далекі
З тобою все розділять на землі!

Приспів.    Авторська пісня','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4411736'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4411736','Мої друзі','Де б не бував, в світах,
Чи в ріднім краю,
Тернистих скільки б не пройшов доріг,
Ніколи друзів я не забуваю,
Чекаю вас завжди на свій поріг!

Приспів:
Стрімка вода гойдає береги,
Пливуть за обрій почуття іллюзій
Та найдорожчими на всі роки
Зостануться у світі мої друзі!

Згадаймо все із вечора до ранку,
Бажання загадають нам зірки,
Залишимо у серці наостанку
Ми тільки щиру дружбу на віки!

Приспів.

Нехай летять у синю даль лелеки,
Нехай життя, то радощі й жалі
І тільки друзі близькі і далекі
З тобою все розділять на землі!

Приспів.    Авторська пісня');
