INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4414939','Свято Божого Різдва','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'За столом уся родина,
І до Бога всі слова -
То святкує Україна
Свято Божого Різдва!

Приспів:
І коли зоря на небі,
Наче добрий знак зійде,
То у мене і у тебе
В серці віра розцвіте!

За столом уся родина,
У молитві всі серця,
І радіє Україна
І за Сина й за Отця!

Приспів.

І святкує Україна,
І родина - за столом,
Тут Господь,
Святий, єдиний,
Душі сповнює добром!

Приспів.','["pisni.org.ua", "cat:kolyadky", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Колядки", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4414939'), datetime('now')),datetime('now'));
