INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4413685','Крокує Новий рік','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'До нас прийшла зима,
Тепла ніде нема,
Лиш вітер, буревій!
Та чую голос твій,
Горобчику малий,
Мій друже запальний!

Приспів:
Цвірінь-цвірінь-цвірінь,
Яка у неба синь!
І сонечко для всіх!
Цвірінь-цвірінь-цвірінь,
Журитися покинь,
Бо скоро Новий рік!
Кружляє білий сніг!
Крокує Новий рік!

Бурульки чарівні
Малює на вікні
Мороз без олівця,
І радісно мені,
Що слухаю пісні
Малого горобця!

Приспів.','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4413685'), datetime('now')),datetime('now'));
