INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_441236','Ой не шуми, луже','Українська народна пісня. Виконує: Подільські музики','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Ой не шуми, луже,
Зелений байраче!...
Не плач, не журися,   |
Молодий козаче!       | (2)

Не сам же я плачу -
Плачуть карі очі,
Що нема спокою        |
Ані вдень, ні в ночі. | (2)

Сусіди близькії -
Вороги тяжкії:
Не дають ходити,      |
Дівчину любити.       | (2)

Я ж буду ходити
І буду любити,
Ще й до себе візьму - |
Буду з нею жити!      | (2)

Ой умруя, милая...
Як ти будеш жива -
Чи згадаєш, мила,     |
Де моя могила?        | (2)

А моя могила
Край синього моря,
Де була між нами      |
Тихая розмова!        | (2)

Зійдеш на могилу,
Та не сумуй друже,
Спогадають люди,      |
Що любилось друже!    | (2)

Зійдеш на могилу -
Не труси землею,
Бо сама вважаєш,      |
як тяжко під нею!     | (2)

Ой тим воно тяжко -
Любилися важко
Тим воно тяженько -   |
Любились вірненько!   | (2)','["pisni.org.ua", "cat:kozacki", "Козацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_441236'), datetime('now')),datetime('now'));
