INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4413838','На Різдво!','Музика: Ірина Федишин Слова: Ірина Федишин, Віталій Човник. Виконує: Ірина Федишин','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'А на Різдво!.. На Різдво!..
Під ногами сніг рипучий,
За вікном зима,
Мерехтять вогні надворі,
Всюди метушня...
Сніг присипав всі дороги,
Замітав сліди,
А як з неба впаде промінь,
Йдуть колядники!
Раз на рік така зима!

Приспів:
А на Різдво!.. На Різдво      |
Я їду туди, де виросла давно! |
На Різдво!.. А на Різдво      |
Я їду туди, де виросла давно! | (2)

Поруч найрідніші люди,
Ніч несе добро,
Кожну хату обіймає
Ласкою тепло!
А якщо на серці сумно,
Знай, що на Різдво
З неба ангели злітають,
Огорта крилом!
Раз на рік така зима!

Приспів.

А на Різдво в казкову ніч
Стаються справжні дива!
Справжні дива!..
Ця ніч - Різдво!..

Приспів.','["pisni.org.ua", "cat:kolyadky", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Колядки", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4413838'), datetime('now')),datetime('now'));
