INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4419236','Друзі','Музика: Леся Горова Слова: Леся Горова. Виконує: Леся Горова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я вибираю друзів,
Щоби поруч із ними йти,
Я вибираю друзів,
Щоб любити і берегти!
Є у моєму колі
Сестра і по духу брат,
Кожен, хто прагне волі,
І не відступає назад!

Приспів:
Гей, мої друзі,
Озовіться скільки вас?
Гей, мої друзі,
Хай багато буде нас!
Гей, мої друзі,
Не полова, а зерно!
Хай здіймається над нами
Жовто-синє знамено!
Хай здіймається над нами
Наше знамено!

Я вибираю в друзі
Невипадкових людей,
В кого незламне серце
