INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_441532','Святий Яне','Українська народна пісня. Виконує: Піккардійська Терція','uk','ukraine_before_1917',NULL,NULL,'Альбом "Сад ангельських пісень", 1997 р. http://tercia.alfaspace.net/album2.html',NULL,'На Святого Яна собітку палили,
