INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4419389','У моєї доні','Музика: Леся Горова Слова: Леся Горова. Виконує: Леся Горова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'У моєї доні сонечко в долоні,
В оченятах небо, в усмішці весна,
І ступають доки її маленькі кроки,         |
Там ясний день і темряви нема.             | (2)

У моєї доні квіточка в долоні,
У волоссі вітер, у сльозі кришталь,
Візьму її на руки - і це найкращі ліки,    |
Щоб забути про свою печаль.                | (2)

Я своєї доні поцілую скроні,
І малу голівку радо обійму,
Хай дзвенить дзвіночок - ніжний голосочок, |
А я тихенько відповім йому.                | (2)

У моєї доні ягідки червоні,
Кислі і солодкі, як вона сама.
Я знаю, що для мене у цілому світі         |
Кращої, ріднішої нема!..                   | (2)

Кращої, ріднішої нема!..','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4419389'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4419389','У моєї доні','У моєї доні сонечко в долоні,
