INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4417539','Маленький Ангелик','Музика: Лілія Вікарук Слова: Лілія Вікарук. Виконує: Лілія Вікарук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Маленький Ангелик із неба злетів
І звістку веселу для нас сповістив,
Що Діва Пречиста, Господня Невіста
Синочка для нас зродила!..
Синочка для нас зродила!..

Неначе ліхтарик, маленьку зорю
Ангелик узяв у долоньку свою,
Щоб шлях освітити і всім сповістити,
Що Господь прийшов у наш світ!..
Що Господь прийшов у наш світ!..

А та зоря ясна барвисто сіяє
І шлях до Христа нам усім осяває!
Щоб ми помолились, Йому поклонились,
Бо Він - наш Господь і наш Спас!..
Бо Він - наш Господь і наш Спас!..

Схилімось і ми із малим Ангелятком
До ясел чудних із Господнім Дитятком,
Яке всіх приймає і благословляє,
І свою любов усім шле!..
І свою любов усім шле!..','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4417539'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4417539','Маленький Ангелик','Маленький Ангелик із неба злетів
І звістку веселу для нас сповістив,
