INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4421032','Впавши на коліна','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Впавши на коліна, поклін віддаю,
Кланяюсь доземно хресту Твоєму!
Правою рукою три рази хрещусь,
Боже, Тебе кличу, Тобі я молюсь!

Відчуваю подих, що лине від Христа,
Немов в ніжнім вітрі ідемо в життя!
Страх, тремтіння тіла, мов живу вві сні...
Злі, брудні провини - це мука для душі...

То цей ніжний вітер - подих святих сил -
Гладить, пригортає... Бог мене простив!
Надприроднє диво, наче гарний сон,
Душу очищає, бореться зі злом...

Безпека, радість, спокій, мир біля Христа,
До дерева святого тулюсь - обніма.
І хрест розпустився цвітом неземним,
Бо з''єдналось серце з подихом святим.

Впавши на коліна, поклін віддаю,
Кланяюсь доземно хресту Твоєму,
Хресту Твоєму!','["pisni.org.ua", "cat:strasni", "Страсні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4421032'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4421032','Впавши на коліна','Впавши на коліна, поклін віддаю,
Кланяюсь доземно хресту Твоєму!
Правою рукою три рази хрещусь,
Боже, Тебе кличу, Тобі я молюсь!

Відчуваю подих, що лине від Христа,
Немов в ніжнім вітрі ідемо в життя!
Страх, тремтіння тіла, мов живу вві сні...
Злі, брудні провини - це мука для душі...

То цей ніжний вітер - подих святих сил -
Гладить, пригортає... Бог мене простив!
Надприроднє диво, наче гарний сон,
Душу очищає, бореться зі злом...

Безпека, радість, спокій, мир біля Христа,
До дерева святого тулюсь - обніма.
І хрест розпустився цвітом неземним,
Бо з''єдналось серце з подихом святим.

Впавши на коліна, поклін віддаю,
Кланяюсь доземно хресту Твоєму,
Хресту Твоєму!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4413389','В темную нічку','Музика: ієродиякон Іпатий (Малютін), Марта Лозинська Слова: ієродиякон Іпатий (Малютін), Тереза Угрин','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'В темную нічку, над Вифлеємом,
Ясна зоря зійшла,
Світлом землю покрила.
Пречиста Діва, свята Невіста,
В вертепі бідному Синочка зродила.

Приспів:
Спи, Ісусе, спи, маленький,
Спи, Ти, зірочко, моя.
Твою долю, мій миленький,
Тобі співаю я...

Ніжно цілувала, пеленою вкрила,
Поклала спати, тихо пісню завела:
Виростеш, Ти, Синку,
Станеш Ти дорослим,
У світі підеш, Дитиночка Моя...

Приспів.

Любов Господню і Божу правду
Ти, світом віри, людям своїм поенесеш,
Правда буде жити, гріха окови розіб''є,
Но на Голгофі умре Дитятко моє...

Приспів.

Спи, Ісусе, спи, маленький,
Спи, Ти - мій рожевий цвіт,
І з надією на Тебе
Дивиться увесь світ!','["pisni.org.ua", "cat:kolyadky", "Колядки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4413389'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4413389','В темную нічку','В темную нічку, над Вифлеємом,
Ясна зоря зійшла,
Світлом землю покрила.
Пречиста Діва, свята Невіста,
В вертепі бідному Синочка зродила.

Приспів:
Спи, Ісусе, спи, маленький,
Спи, Ти, зірочко, моя.
Твою долю, мій миленький,
Тобі співаю я...

Ніжно цілувала, пеленою вкрила,
Поклала спати, тихо пісню завела:
Виростеш, Ти, Синку,
Станеш Ти дорослим,
У світі підеш, Дитиночка Моя...

Приспів.

Любов Господню і Божу правду
Ти, світом віри, людям своїм поенесеш,
Правда буде жити, гріха окови розіб''є,
Но на Голгофі умре Дитятко моє...

Приспів.

Спи, Ісусе, спи, маленький,
Спи, Ти - мій рожевий цвіт,
І з надією на Тебе
Дивиться увесь світ!');
