INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_442287','Ой Верше Мій Верше (8-9)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Лемківські співанки. Зібрав і упорядкував М. Соболевський. — К.: Музична Україна, 1967. — 320 с.','Пісня з добірки М.Соболевського: Лемківські співанки Діалектизми: барз - дуже; было - було; виросне - виросте; добрі - добре; кади - куди; мі - мені; свойой - своєї; тогди - тоді; юж - вже.','Ой Верше Мій Верше
Мій Зелений Верше
Юж мі так не буде  |(2) |
Як мі было перше        |(2)

Бо перше мі было
Барз добрі мі было
Од свойой Мамички  |(2) |
Не ходити было          |(2)

Не ходити было
Горами Стежками
Не любити Хлопців  |(2) |
