INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4405430','Не покидай мене, дитинство!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Дуже скоро покинемо іграшки,
Не потрібні нам будуть підручники,
Нас чекатимуть справи дорослі, не малі!
Але нам не забути рідних двориків,
Де літали у космос, грали в козаків,
Де уперше торкнуся я твоєї руки...

Приспів:
Не покидай мене, дитинство, не покидай!..
Дитячу іскру в моїм серці залиши!
Не покидай мене, дитинство, не покидай!..
Нехай живе любов дитяча у душі!

Прийде час, мабуть, ми не помітимо,
Як у світ цей дорослий ми прийдемо.
Нас закрутять численні турботи та діла.
Інститути, контори і офіси,
Реферати, доклади та описи,
А у школі перерва й перша любов була...

Приспів.

Не покидай мене, дитинство, не покидай!..
Нехай живе любов дитяча у душі!
Нехай живе любов дитяча у душі!','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4405430'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4405430','Не покидай мене, дитинство!','Дуже скоро покинемо іграшки,
