INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4419532','Хрест Ісуса прославім','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'усне передання','https://youtu.be/2B_xFPYz4rE Пісню виконує хор церкви Благовіщення (с. Куровичі).','Хрест Ісуса прославім,
Цвяхи і вінець терновий,
Там спасення і життя
Ми знайдем в Христовій Крові.
Слава Тобі, Спасителю,
Слава, слава Твому хресту!

Хрест Ісуса прославім,
Дерево життя цвітуще,
З нього кров свята пливе,
Мов бальзам живий цілющий.
Слава Тобі, Спасителю,
Слава, слава Твому хресту!

Хрест Ісуса прославім,
Ту криницю ласк безмірних,
На душевні рани лік
В бою з пеклом друг наш вірний.
Слава Тобі, Спасителю,
Слава, слава Твому хресту!

Хрест Ісуса прославім,
Бо на ньому вмер Спаситель,
Хрест до серця пригорніть,
З нього вчімося краще жити.
Слава Тобі, Спасителю,
Слава, слава Твому хресту!

Хрест Ісуса прославім,
Дорогий він нам, о, Христе,
Висіло на нім твоє
Тіло красне і пречисте.
Слава Тобі, Спасителю,
Слава, слава Твому хресту!

Хрест Ісуса прославім,
Там любив він нас до краю
І подав нам хрест святий,
Ключ до неба, шлях до раю.
Слава Тобі, Спасителю,
Слава, слава Твому хресту!

То не дерево хреста
Прославляють християни,
Лиш Ісуса, що терпів
Слава Тобі, Спасителю,
Слава, слава Твому хресту!','["pisni.org.ua", "cat:strasni", "Страсні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4419532'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4419532','Хрест Ісуса прославім','Хрест Ісуса прославім,
Цвяхи і вінець терновий,
Там спасення і життя
Ми знайдем в Христовій Крові.
Слава Тобі, Спасителю,
Слава, слава Твому хресту!

Хрест Ісуса прославім,
Дерево життя цвітуще,
З нього кров свята пливе,
Мов бальзам живий цілющий.
Слава Тобі, Спасителю,
Слава, слава Твому хресту!

Хрест Ісуса прославім,
Ту криницю ласк безмірних,
На душевні рани лік
В бою з пеклом друг наш вірний.
Слава Тобі, Спасителю,
Слава, слава Твому хресту!

Хрест Ісуса прославім,
Бо на ньому вмер Спаситель,
Хрест до серця пригорніть,
З нього вчімося краще жити.
Слава Тобі, Спасителю,
Слава, слава Твому хресту!

Хрест Ісуса прославім,
Дорогий він нам, о, Христе,
Висіло на нім твоє
Тіло красне і пречисте.
Слава Тобі, Спасителю,
Слава, слава Твому хресту!

Хрест Ісуса прославім,
Там любив він нас до краю
І подав нам хрест святий,
Ключ до неба, шлях до раю.
Слава Тобі, Спасителю,
Слава, слава Твому хресту!

То не дерево хреста
Прославляють християни,
Лиш Ісуса, що терпів
Слава Тобі, Спасителю,
Слава, слава Твому хресту!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_442333','Ой, служив я в пана...','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Ой, служив я в пана, та й на перше літо,
Заробив я в пана курочку за літо.

А та кура-чубатура по садочку ходить та й ходить
І курчаток водить та й водить...

Ой, служив я в пана, та й на друге літо,
Заробив я в пана качечку за літо.

А та кача дрібно скаче,
А та кура-чубатура по садочку ходить та й ходить
І курчаток водить та й водить...

Ой, служив я в пана, та й на третє літо,
Заробив я в пана індика за літо.

А той індик, пиндик-пиндик,
А та кача дрібно скаче,
А та кура-чубатура по садочку ходить та й ходить
І курчаток водить та й водить...

Ой, служив я в пана, на четверте літо,
Заробив я в пана баранця за літо.

А той баран круторогий, заліз бабі поміж ноги,
А той індик, пиндик-пиндик,
А та кача дрібно скаче,
А та кура-чубатура по садочку ходить та й ходить
І курчаток водить та й водить...

Ой, служив я в пана, та й на п"яте літо,
Заробив я в пана корову за літо.

А корова му-му-му.
А той баран круторогий, заліз бабі поміж ноги,
А той індик, пиндик-пиндик,
А та кача дрібно скаче,
А та кура-чубатура по садочку ходить та й ходить
І курчаток водить та й водить...

Ой, служив я в пана, та й на шосте літо,
Заробив я в пана та й бика за літо.

А той бик корові втик,
А корова му-му-му.
А той баран круторогий, заліз бабі поміж ноги,
А той індик, пиндик-пиндик,
А та кача дрібно скаче,
А та кура-чубатура по садочку ходить та й ходить
І курчаток водить та й водить...

Ой, служив я в пана, тай на сьоме літо,
Заробив я в пана дівчину за літо.

А та дівка напилася, впала з печі й забилася,
А той бик корові втик,
А корова му-му-му.
А той баран круторогий, заліз бабі поміж ноги,
А той індик, пиндик-пиндик,
А та кача дрібно скаче,
А та кура-чубатура по садочку ходить та й ходить
І курчаток водить та й водить...

Акорди від Bohdanko (www.pisni.org.ua):

Ой, служив я в пана, та й на перше літо,
Заслужив я в пана курочку за літо.

А та кура-чубатура по садочку ходить та й ходить
Куряточок водить та й водить...','["pisni.org.ua", "cat:narodni", "cat:volynski", "cat:zhartivlyvi", "Народні пісні", "Пісні з Волині", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_442333'), datetime('now')),datetime('now'));
