INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4419434','О, Господи, о, як я Вас люблю','Музика: Володимир Мухар Слова: Степан Галябарда. Виконує: Ольга Щербакова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я вперше у житті Вас полюбила,
Здавалося тоді спинився час...
За Вами всюди тінню я ходила,
Та погляд Ваш мене не замічав...
Я в цілому світі місця вже не мала,
І з розпачу життя уже пішла,
Але любов мене не відпускала
І спокою знайти я не могла...

Приспів:
О, Господи, о, як я Вас люблю!..
І бачу кожен день перед собою,
Ви тільки не згасіть свічу мою
Байдужою, холодною рукою!..

І Ви прийшли, коли я вже й не ждала,
Лиш вогник тлів у попелі душі,
І знов моє кохання запалало,
І знов ми з Вами рідні, не чужі.
Ви лиш промовте те єдине слово,
Яке у серці бродить, як вино,
Бо я в обитель ніжності й любові
Вже браму відчинила Вам давно!..

Приспів.

Ви тільки не згасіть свічу мою
Байдужою, холодною рукою!..
О, Господи, о, як я Вас люблю!..','["pisni.org.ua", "cat:romansy", "Романси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4419434'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4419434','О, Господи, о, як я Вас люблю','Я вперше у житті Вас полюбила,
