INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_4419434_l1','pisniua_4419434','YouTube','https://www.youtube.com/watch?v=I8u8kHFw5T8','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4424232','Різдво','Музика: Кость Фастівець Слова: Кость Фастівець. Виконує: GONTA','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ой, новина, в нас новина:
Породила Діва Сина,
І у яселка поклала,
Пеленами сповивала.
Перед тим малим Дитятком
Стали пастушки з ягнятком,
На колінця припадають,
Царя Бога вихваляють!
І ми вийдемо всі з хати,
Щоби разом святкувати Різдво!
Святкуємо Різдво!
Різдво! Святкуємо Різдво!

В небі зірка засвітила,
Нам новину сповістила,
Що вже годі сумувати,
Будемо Різдво стрічати.
На столах святкові страви,
Всі готові до забави,
Будем колядки співати,
Подарунки дарувати!
За столом уся родина
І святкує Україна Різдво!
Святкуємо Різдво!
Різдво! Святкуємо Різдво!

Вогник свічечки палає,
Ми бажання загадаєм,
Щоб жили ми всі здорові
В мирі, злагоді й любові!
Щоби жито колосилось,
Щоби діточки родились,
Щоб частіше посміхались,
Щоби мрії всі збувались!
Ми бажання загадаєм
І всі разом заспіваєм на Різдво!
Святкуємо Різдво!
Різдво! Святкуємо Різдво!
Різдво! Святкуємо Різдво!
Різдво! Святкуємо Різдво!
Святкуємо Різдво!','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4424232'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4424232','Різдво','Ой, новина, в нас новина:
Породила Діва Сина,
І у яселка поклала,
Пеленами сповивала.
Перед тим малим Дитятком
Стали пастушки з ягнятком,
На колінця припадають,
Царя Бога вихваляють!
І ми вийдемо всі з хати,
Щоби разом святкувати Різдво!
Святкуємо Різдво!
Різдво! Святкуємо Різдво!

В небі зірка засвітила,
Нам новину сповістила,
Що вже годі сумувати,
Будемо Різдво стрічати.
На столах святкові страви,
Всі готові до забави,
Будем колядки співати,
Подарунки дарувати!
За столом уся родина
І святкує Україна Різдво!
Святкуємо Різдво!
Різдво! Святкуємо Різдво!

Вогник свічечки палає,
Ми бажання загадаєм,
Щоб жили ми всі здорові
В мирі, злагоді й любові!
Щоби жито колосилось,
Щоби діточки родились,
Щоб частіше посміхались,
Щоби мрії всі збувались!
Ми бажання загадаєм
І всі разом заспіваєм на Різдво!
Святкуємо Різдво!
Різдво! Святкуємо Різдво!
Різдво! Святкуємо Різдво!
Різдво! Святкуємо Різдво!
Святкуємо Різдво!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_4424232_l1','pisniua_4424232','YouTube','https://www.youtube.com/watch?v=MNrWXjN0jWc','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4425083','Гімн Спеціалізованої школи №196','Музика: народна Слова: І. Олейничук','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Гімн Спеціалізованої школи №196 Святошинського району м. Києва.','Чесність, щирість, добро,
Справедливість і демократизм -
Це основа шкільної родини:
Один Дев''ять Шість!
В благороднім прагненні
Ми щастя поєднались,
Мови різні, наче свою рідну,
Знати тут бажаєм.

Мудрість предків, козацька слава,
"Кобзар" - оберіг,
Земля рідна - ненька Україна -
Наш одвічний світ!
Так навчають учнів в нашій школі -
Один Дев''ять Шість, -
Щоб в майбутнім рідну Україну
Кожен з нас любив й беріг!

Скарб найбільший нам дарує школа -
Науку життя!
Пісня й праця - дві великі сили,
Мов жива вода.
Сонцелика школа - Берегиня -
Один Дев''ять Шість -
Захища нас, наче мати рідна,
Всіх від зла, незгод та лих!

Щоб не зрадив світ нас
У майбутнім, школа всіх навча:
Шанувати понад все Людину,
Матір і Дитя!
Щирі серцем, чисті ми душею
Тут стаємо!
Україні громадянську вірність
Чесно принесемо!

Процвітай же, рідна наша школо,
Світ барвистих мрій!
Хай душа творця не переквітне
В благородстві дій!
Хай в серцях сіяє сонцеквітно:
Один Дев''ять Шість!
Хай узнають про здобутки школи
Україна й увесь світ!','["pisni.org.ua", "cat:himny-marshi", "Гимни та марші"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4425083'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4425083','Гімн Спеціалізованої школи №196','Чесність, щирість, добро,
Справедливість і демократизм -
Це основа шкільної родини:
Один Дев''ять Шість!
В благороднім прагненні
Ми щастя поєднались,
Мови різні, наче свою рідну,
Знати тут бажаєм.

Мудрість предків, козацька слава,
"Кобзар" - оберіг,
Земля рідна - ненька Україна -
Наш одвічний світ!
Так навчають учнів в нашій школі -
Один Дев''ять Шість, -
Щоб в майбутнім рідну Україну
Кожен з нас любив й беріг!

Скарб найбільший нам дарує школа -
Науку життя!
Пісня й праця - дві великі сили,
Мов жива вода.
Сонцелика школа - Берегиня -
Один Дев''ять Шість -
Захища нас, наче мати рідна,
Всіх від зла, незгод та лих!

Щоб не зрадив світ нас
У майбутнім, школа всіх навча:
Шанувати понад все Людину,
Матір і Дитя!
Щирі серцем, чисті ми душею
Тут стаємо!
Україні громадянську вірність
Чесно принесемо!

Процвітай же, рідна наша школо,
Світ барвистих мрій!
Хай душа творця не переквітне
В благородстві дій!
Хай в серцях сіяє сонцеквітно:
Один Дев''ять Шість!
Хай узнають про здобутки школи
Україна й увесь світ!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4405889','Школа - весела сім''я!','Музика: Олег Антоняк Слова: Алла Орел','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ідемо до школи вранці
І дівчата, і хлопчаки,
І лежать у кожнім ранці
Ручки, зошити й книжки.
Чи уроки ми повчили -
Це питання не просте,
Може щось не доробили,
Та для дружби це пусте!

Приспів:
Школа - весела сім''я! |
Школа - це друзі і я, |
Радість і втіха,      |
Пригорщі сміху!       |
Школа - весела сім''я! | (2)

Ми веселі, пустотливі,
Вчителям турбот вагон,
Але дружні і щасливі,
Дружба, то шкільний закон!
Ми і сваримось завзято,
Ми і миримось на вік!
Пролітають будні, свята,
Ще один минає рік!

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4405889'), datetime('now')),datetime('now'));
