INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4425532','Перше вересня завжди приходить вчасно','Музика: В''ячеслав Топільницький Слова: В''ячеслав Топільницький. Виконує: Ніночка Козій','uk','ukraine_1991',NULL,NULL,'1. аудіозапис 2. http://www.tinytunes.pp.ua/2023/06/blog-post_49.html',NULL,'Сьогодні осінь нам подарувала
Цей радісний день! Перший свій день!
Вона до школи погукала безліч
Цікавих гостей, батьків і дітей!
Вона уже підготувала квіти
Духмяні, п''янкі в дарунок для нас!
І вже усміхнені, веселі діти
Поспішають у клас!

Приспів:
А перше вересня
Завжди приходить вчасно!
Ми перше вересня
Усі зустрінем класно!
Ми привітаєм один одного
З початком навчання!
Зібралась тут
Уся шкільна рідня!
Ми привітаєм один одного
З початком навчання:
З першим вересня!

Нові підручники в нових портфелях
Чекають давно свій перший урок!
І першокласниця, як юна фея,
Тримає в руках співучий дзвінок.
Його мелодією чарівною
Милуються всі: дорослі й малі!
Він розливається у даль луною
По рідній землі!

Приспів. (2)','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4425532'), datetime('now')),datetime('now'));
