INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_442838','Ой попід Гай Зелененький (1)','(Брало Дівча Лен Дрібненький). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Лемківські співанки. Зібрав і упорядкував М. Соболевський. — К.: Музична Україна, 1967. — 320 с.','Пісня з добірки М.Соболевського: Лемківські співанки Діалектизми: дакому - якомусь; дунаєчок - будь-яка річка; лен - льон; хоц - хоч; ци - чи.','Ой попід Гай ой попід Гай Зелененький
Брало Дівча Лен Дрібненький           |(2)

Ой як брало ой як брало та й стелило
До Тихого Дунаєчка говорило           |(2)

Ой Дунаю-Дунаєчку Тиха Вода
Кому ж я ся сподобаю так Молода       |(2)

Ци Попови ци Дякови ой дай Боже
Ци дакому гультайови не дай Боже      |(2)

Не дай мене Моя Мамцю за пияка
Бо пропаде Худобонька хоц бы яка      |(2)

Але дай мя Моя Мамцю за Такого
Що Він мене вірно любит а я Його      |(2)','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_442838'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_442838','Ой попід Гай Зелененький (1)','Ой попід Гай ой попід Гай Зелененький
