INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4427137','Пісенька горобчика','Музика: З. Компанієць Слова: Петро Синявський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я забув про ігри звичні,
Пластилін і олівець,
Адже біля годівнички
Оселився горобець.
Щоб завжди мене з півслова
Той бешкетник розумів,
Взявся я вивчати мову      |
Невгамовних горобців.      | (2)

Приспів:
Цвірінь-цінь-цінь,
Цвірінь-цінь-цінь,
Друг потрібен нам!
Цвірінь-цінь-цінь,
Цвірінь-цінь-цінь,
Навіть горобцям!

Мав цікаву я роботу -
Горобця дресирував,
Скільки різних бутербродів
Я пташині згодував!
Та зате, скажіть, де в світі
Є іще такі дива:
Горобець в долоньки плеще, |
І танцює, і співа!         | (2)

Приспів.

Під надійну охорону
Взята мною пташка ця,
Тим-то всі коти району
Поважають горобця!
Друзі, хочу вам сказати,
Що чудова думка ця:
Вже нікому не злякати      |
Гарну пташку - горобця!    | (2)

Приспів.','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4427137'), datetime('now')),datetime('now'));
