INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4424436','Що сказало сонце','Музика: Галина Васіна Слова: Микола Сингаївський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Спитала птаха в сонця
В прозорій вишині:
Де небо найчистіше?
Де краще жить мені?
А сонце усміхнулось,
Заграло у росі:
Лише під мирним небом,
Лише під мирним небом,
Лише під мирним небом
Щасливі ми усі!

Спитала квітка в сонця:
Коли мені цвісти,
Щоб ти для нас тепліше
А сонце усміхнулось,
Заграло у росі:
Лише під мирним небом,
Лише під мирним небом,
Лише під мирним небом
Щасливі ми усі!

Спитали діти в сонця:
Як мир нам зберегти,
Щоб в злагоді і щасті
Жили і ми, і ти?
А сонце усміхнулось:
Ми — як одна сім''я!
Коли щасливі птахи,
Коли щасливі квіти,
Коли щасливі діти,
Щасливе з вами я!','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4424436'), datetime('now')),datetime('now'));
