INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4405134','Ой сивая зозуленька','Українська народна пісня. Виконує: Хор імені Григорія Верьовки','uk','ukraine_before_1917',NULL,NULL,'Джерело: Народні пісні в записах Лесі Українки та з її співу. Записи з голосу Лесі Українки, Миколи Лисенка та Климента Квітки // Упоряд. О. І. Дей та С. Й. Грица. — Київ, 1971, с. 138-140.','Весільна пісня. "Ой сивая зозуленька всенькі сади облітала" — співають друж­ки біля воріт молодої, повертаючись додому після запрошення гостей на весілля. Послухати мелодію та переглянути/завантажити ноти (обробка Миколи Леонтовича) можна тут: https://musescore.com/user/56304587/scores/24453337 Послухати мелодію та переглянути/завантажити ноти (обробка Климентія Домінчена) можна тут: https://musescore.com/user/56304587/scores/24294964','Ой сивая зозуленька
Всенькі сади облітала,
Всенькі сади облітала,
В жодному не кувала.

Прилетіла у вишнев садок —
Там сіла, закувала,
Прилетіла у вишнев садок —
Там сіла, закувала:

Ой, саде ж мій, саде,
Чим я тобі не вгодила?
Ой, саде ж мій, саде,
Чим я тобі не вгодила?

Чи ж я рано не кувала,
Чи росиці не струшала?
Чи ж я рано не кувала,
Чи росиці не струшала?

Молоденька Мар''юся
Всенькі двори обходила,
Всенькі двори обходила,
В жодному не плакала...

А як прийшла під батьків двір, —
Там стала, заплакала.
А як прийшла під батьків двір, —
Там стала, заплакала.

Ой, дворе ж мій, дворе,
Чим я тобі не вгодила?
Ой, дворе ж мій, дворе,
Чим я тобі не вгодила?

Чи ж я рано не вставала,
Чи я тебе не замітала?
Чи ж я рано не вставала,
Чи я тебе не замітала?','["pisni.org.ua", "cat:vesilni", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4405134'), datetime('now')),datetime('now'));
