INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4428931','1 вересня','Музика: Роман Черенов (Morphom) Слова: Роман Черенов (Morphom). Виконує: Morphom','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Це літо змінило нас назавжди,
Хтось, навіть, став тим, ким хотів.
З''явились питання: Як? і куди?
З''явився і шлях, що нас звів.

Приспів:
І ось букет у руці,
Щоб на лінійці в кінці,
Я так чекав цього дня!
Стою з вогнем у очах
Поміж очей у вогнях,
Сьогодні ж перше вересня!

Знову обіцяю бути більш
Уважним в цьому році,
Швидко забуваю -
Нагадає вчитель на уроці.
І ніби народився я в цей день,
Буває несвідомо - порівняти
Можу клас із рідним домом.

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4428931'), datetime('now')),datetime('now'));
