INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_442939','Ой Сусідко','Слова: УСС','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'1. Лемківські співанки. Зібрав і упорядкував М. Соболевський. — К.: Музична Україна, 1967. — 320 с.','Це – лемківський варіант стрілецької пісні на мелодію угорського танцю. Пісня з добірки М.Соболевського: Лемківські співанки Діалектизми: бы-м би я; вандрувати - мандрувати; єй - її; жена - жінка, дружина; лем - тільки; люстерко - дзеркальце; мам - маю; мі - мені; сой - собі; ти - тобі; ту - тут.','Ой Сусідко Сусідко
Пожич же мі Решітко
Я Ти зараз я Ти зараз принесу   |(2)
Лем сой Муку протресу           |

Ой Венґерко Венґерко
Пожич же мі Люстерко
Я Ти зараз я Ти зараз доручу    |(2)
Лем сой Вуса підкручу           |

Мам я Жену Молоду
Не пущу єй по Воду
Могла бы ся могла бы ся втопити |(2)
Мусив бы-м ся женити            |

Ой Дівчино не вір мі
Бо я Хлопец Вандрівний
Я вандрую я вандрую ту і там    |(2)
Де поверну Дівча мам            |','["pisni.org.ua", "cat:lemkivski", "cat:strilecki", "Лемківські пісні", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_442939'), datetime('now')),datetime('now'));
