INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4429838','Рідні вчителі','Музика: Микола Флінта Слова: Віктор Николишин','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Рідна моя школо,
Світ щасливих мрій,
Не забудь ніколи
В пам''яті живій!
Тут росли, вивчали
Ми земне життя,
Шлях свій відкривали
В світле майбуття!

Приспів:
Щастя всім і миру,  |
Рідні вчителі,      |
Вам уклін наш щирий |
Низько до землі!    | (2)

Тут дитинства роки
Радісні пройшли,
Звідси в світ широкий
Мрії понесли!
Юність дарувала
Радість неземну,
Школа об''єднала
Нас в одну сім''ю!

Приспів.

Завжди нам бажали
Злетів в висоти,
Ви допомогали
Віру зберегти!
Всі слова повчання
По життю несем,
Вдячність і вітання
Вам учнівське шлем!

Приспів.

Вам уклін наш щирий
Низько до землі!..','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4429838'), datetime('now')),datetime('now'));
