INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4412535','Лист святому Миколаю','Музика: Віктор Ох Слова: Олена Іськова-Миклащук','uk','ukraine_1991',NULL,'2014','авторське подання','Пісню написано автором 19 грудня 2014 року. Пісню виконує Володя Охріменко.','Виводила донечка букви старанно,
Святому Миколі писала листа:
Я хочу прокинутись з сонечком рано
Від того, що тато мене пригорта...

Не хочу ляльок, і цукерок не треба!
Для інших діток ти віддай шоколад:
Щоб тільки в країні не рвалося небо,
І тато вернувся до мене назад!..

Щоб мама не плакала більше ночами,
Щоб щастям засяяла в неньки весна —
Святий Миколаю, своїми ключами
Ти лихо замкни, що зоветься Війна!

...Прокинулась доня, наївне дитятко,
Співала від щастя й крутилася в лад.
Спинилась в порозі: А де, мамо, татко?..
Розтало дитинство, немов шоколад...','["pisni.org.ua", "cat:svyatyy-mykolay", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4412535'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4412535','Лист святому Миколаю','Виводила донечка букви старанно,
Святому Миколі писала листа:
