INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4430338','Грайливий дощик',NULL,'uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Дощик, з дітками пограй!
Крап-крап-крап!
Нам краплиночки роздай,
Крап-крап-крап!
Весело краплиночкам,
Крап-крап-крап!
Грають без зупиночки,
Крап-крап-крап!

Дощик, дощик, не шуми!
Крап-крап-крап!
Та співаємо й самі,
Крап-крап-крап!
Всі дерева поливай,
Крап-крап-крап!
А маляток не чіпай,
Крап-крап-крап!','["pisni.org.ua", "cat:mifichni", "Пісня з міфічними, світотворчими мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4430338'), datetime('now')),datetime('now'));
