INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4430','Водограй','Музика: Володимир Івасюк Слова: Володимир Івасюк. Виконує: Смерічка, Назарій Яремчук, Софія Ротару, Кобза, Валентина Купріна, Марія Яремчук, Зоряна Юдін','uk','ukraine_before_1917',NULL,NULL,'Червона рута. Пісенник. Київ, Музична Україна, 1993',NULL,'Тече вода, тече бистра,
А куди - не знає,
Поміж гори, в світ широкий
Тече, не вертає.
Ми зустрінемось з тобою
Біля водограю
І попросим його щиро -
Хай він нам заграє.

Приспів:
Ой водо-водограй, грай для нас, грай...
Танок свій жвавий ти не зупиняй.
За красну пісню на всі голоси,
Що хочеш, водограю, попроси.
Струни дає тобі кожна весна,
Дзвінкість дарує їм осінь ясна.
І ми заграєм на струнах твоїх -
Хай розіллють вони радісний сміх.

Подивись, як сіру скелю
Б''є вода іскриста,
Ти зроби мені з тих крапель
Зоряне намисто.
Краще я зберу джерела
Й з них зроблю цимбали,
Щоб тобі, дівчино мила,
вони красно грали

Приспів','["pisni.org.ua", "cat:lirychni", "Пісні про кохання, ліричні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4430'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4430','Водограй','Тече вода, тече бистра,
