INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4429939','Учителі, Ви посміхніться','Музика: Руслан Горобець Слова: невідомий','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ми всі зібрались
В цій прекрасній залі,
Щоб привітати наших вчителів!
За працю їх
Доземно всім вклонитись,
І побажати вдячних школярів!

Приспів:
Учителі, Ви посміхніться,
Дарують квіти вам в цей день!
Недуги Вас хай обминають,     |
Повага й шана буде від людей! | (2)

Чи сніг, чи дощ, а Ви усе до школи,
Що й не злічити скільки було днів...
Щодня Ви сієте розумне й добре,
А урожай - це вдячні школярі!

Приспів.

Ми всі зібрались
В цій прекрасній залі,
Щоб привітати наших вчителів!
За працю їх
Доземно всім вклонитись,
І побажати вдячних школярів!

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4429939'), datetime('now')),datetime('now'));
