INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4428838','Ми йдемо сьогодні в клас','Музика: Микола Дремлюга Слова: Марія Пригара','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ми ще звечора поклали
У портфелі букварі.
Ми в віконце виглядали,
Прокидались на зорі.

Приспів:
Сонце, сонечко, зійди,
Нас удосвіта збуди!
Ми йдемо сьогодні в клас —
В перший раз!

Ось і сонечко над нами,
Час до школи, швидко в путь!
Де не глянеш — із книжками
Першокласники ідуть!

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4428838'), datetime('now')),datetime('now'));
