INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4422737','Минають дні, минають ночі','Музика: Pivovarov Production Слова: Тарас Шевченко. Виконує: Артем Пивоваров, ЯрмаК','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Минають дні, минають ночі,
Минає літо, шелестить і гаснуть очі,
Знов минають, знов минають,
Знов минають, знов минають ночі,
Знов минають ночі,
Минають дні, минають ночі...

Минають дні, минають ночі,
Манає літо, шелестить
Пожовкле листя, гаснуть очі,
Заснули думи і серце спить...
І все заснуло, і не знаю,
Чи я живу, чи доживаю,
Чи так по світу все волочусь,
Бо вже не плачу й не сміюсь...

Доле, ти де? Доле, ти де?
Нема ніякої...
Коли доброї жаль, Боже,
То дай злої, злої!
Не дай спати ходячому,
Серцем замирати
І гнилою колодою
В цьому світу валятись...
А дай жити, серцем жити
І людей щиро любити,
А як ні, то проклинать
І світ Божий запалити!
Страшно впасти у кайдани,
Умирать в неволі,
А ще гірше — спати й спати,
Брате, і спати на волі...

І все заснуло, і я не знаю     |
Чи то живу, чи доживаю,        |
Чи так по світу волочусь,      |
Бо вже не плачу й не сміюсь... | (2)','["pisni.org.ua", "cat:philosophic", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4422737'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4422737','Минають дні, минають ночі','Минають дні, минають ночі,
Минає літо, шелестить і гаснуть очі,
Знов минають, знов минають,
Знов минають, знов минають ночі,
Знов минають ночі,
Минають дні, минають ночі...

Минають дні, минають ночі,
Манає літо, шелестить
Пожовкле листя, гаснуть очі,
Заснули думи і серце спить...
І все заснуло, і не знаю,
Чи я живу, чи доживаю,
Чи так по світу все волочусь,
Бо вже не плачу й не сміюсь...

Доле, ти де? Доле, ти де?
Нема ніякої...
Коли доброї жаль, Боже,
То дай злої, злої!
Не дай спати ходячому,
Серцем замирати
І гнилою колодою
В цьому світу валятись...
А дай жити, серцем жити
І людей щиро любити,
А як ні, то проклинать
І світ Божий запалити!
Страшно впасти у кайдани,
Умирать в неволі,
А ще гірше — спати й спати,
Брате, і спати на волі...

І все заснуло, і я не знаю     |
Чи то живу, чи доживаю,        |
Чи так по світу волочусь,      |
Бо вже не плачу й не сміюсь... | (2)');
