INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_443185','Налетіли журавлі','Українська народна пісня. Виконує: Тріо Мареничів','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Налетіли журавлі,
Налетіли журавлі,
Сіли-впали на ріллі,
Сіли-впали на ріллі.

Де журавка ходила,
Де журавка ходила -
Там пшениця вродила,
Там пшеничка вродила.

Де журавель походив,
Де журавель походив -
То там кукіль уродив,
То там кукіль уродив.

Краща жінка первая,
Краща жінка первая,
Аніж тая другая,
Аніж тая другая.

Що з первою діток мав,
То з другою розігнав.

Ходить батько по лану,
Ходить батько по лану,
Кличе діти додому,
Кличе діти додому.

Ідіть, дітки, додому
Ідіть, діти, додому
Не буде вам розгону,
Не буде вам розгону.

Живіть, тату, тепер сам,
Живіть, тату, тепер сам,
Як молоду жінку взяв,
Як молоду жінку взяв.

А ми будем служити,
А ми будем служити,
Чужим батькам годити,
Чужим батькам годити.

А ми будем зароблять,
А ми будем зароблять,
Та матінку поминать,
Та матінку поминать','["pisni.org.ua", "cat:pro-batkiv", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_443185'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_443185','Налетіли журавлі','Налетіли журавлі,
Налетіли журавлі,
