INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4434131','Святий Миколай','Слова: Роман Завадович','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'На небі зорі, зорі,
Поля снігами занесло,
В киреї білій все село,
А місто в світла морі.
По полі вітер віє,
Що вирвався десь з-поміж лоз,
По селах тріскотить мороз,
Але в дітей надії.

У місті та по селах
Сплять діточки у постелях,
І усмішка в них на устах
Щаслива та весела!
В сні бачать: білі коні
З санками мчаться попід гай,
В санках святитель Миколай,
Санки дарунків повні!

Ось коні вже край хати,
Вже Миколай у хату йде,
Діткам під подушки кладе
Даруночків багато!
В хатині чи в покою
Спиняється Він ще на мить
І діточок благословить
Правицею святою:

Ростіте, любі діти,
Минайте всі дороги злі,
Для Бога й рідної землі
Хай шлях один вам світить!
А рано, як світає,
Під подушкою вмить рука
Дарунків гарних вже шука
Святого Миколая!','["pisni.org.ua", "cat:svyatyy-mykolay", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4434131'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4434131','Святий Миколай','На небі зорі, зорі,
Поля снігами занесло,
В киреї білій все село,
А місто в світла морі.
По полі вітер віє,
Що вирвався десь з-поміж лоз,
По селах тріскотить мороз,
Але в дітей надії.

У місті та по селах
Сплять діточки у постелях,
І усмішка в них на устах
Щаслива та весела!
В сні бачать: білі коні
З санками мчаться попід гай,
В санках святитель Миколай,
Санки дарунків повні!

Ось коні вже край хати,
Вже Миколай у хату йде,
Діткам під подушки кладе
Даруночків багато!
В хатині чи в покою
Спиняється Він ще на мить
І діточок благословить
Правицею святою:

Ростіте, любі діти,
Минайте всі дороги злі,
Для Бога й рідної землі
Хай шлях один вам світить!
А рано, як світає,
Під подушкою вмить рука
Дарунків гарних вже шука
Святого Миколая!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4430930','Осінь плакала','Музика: Сергій Єрмолаєв, Андрій Ігнатченко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Швидесенько надворі осінь прийшла
І довгі коси свої знову розплела,
І журавлі курличуть вдаль,
Та знай, це гра її, менше слів,
В серці печаль...
І листячко дубове жовкне й спада,
Тихесенько з гілочок вітер позіха,
І дощик йде, що треба ще?..
Дай серцю під плащем -
Менше слів... Осінь прийшла!

Прийшла вже знов пора і листя обпада,  |
І журавлі летять у далеку даль...      |
І скрізь нове вбрання, яскраве золоте, |
А все одно на серці у нас печаль...    |
Осіння це пора і сонце вигляда,        |
І "жовта" знов до літа балакала...     |
Краса в нас золота і грає дітвора,     |
А осінь знову дощиком плакала...       | (2)','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4430930'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4430930','Осінь плакала','Швидесенько надворі осінь прийшла
І довгі коси свої знову розплела,
І журавлі курличуть вдаль,
Та знай, це гра її, менше слів,
В серці печаль...
І листячко дубове жовкне й спада,
Тихесенько з гілочок вітер позіха,
І дощик йде, що треба ще?..
Дай серцю під плащем -
Менше слів... Осінь прийшла!

Прийшла вже знов пора і листя обпада,  |
І журавлі летять у далеку даль...      |
І скрізь нове вбрання, яскраве золоте, |
А все одно на серці у нас печаль...    |
Осіння це пора і сонце вигляда,        |
І "жовта" знов до літа балакала...     |
Краса в нас золота і грає дітвора,     |
А осінь знову дощиком плакала...       | (2)');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_4430930_l1','pisniua_4430930','YouTube','https://www.youtube.com/watch?v=knph7uVpXco','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4433436','Остання путь від рідного порога','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудыозапис',NULL,'Остання путь, остання путь,
Останняя дорога...
Остання путь, остання путь    |
Від рідного порога...         | (2)

А тая путь така трудна,
Нікого не минає,
Який народ туди іде,          |
То звідти не вертає..         | (2)

Ізвідти не вертається
Ні бідний, ні багатий,
Коли прийшла кому пора,       |
То треба помирати...          | (2)

Тіло в могилу покладуть,
Душа піде на небо.
З собой багатства не візьмеш, |
Бо там його й не треба!..     | (2)

А ви, рідня моя й друзя,
За мене потрудіться,
І за впокой моєй душі         |
Ви Богу помоліться!..         | (2)','["pisni.org.ua", "cat:nostalgia", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4433436'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4433436','Остання путь від рідного порога','Остання путь, остання путь,
