INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4434333','Емігрантська','Музика: Іван Чегель, Іван Попович, Юрій Васильківський Слова: Іван Чегель. Виконує: Іван Попович','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Мов ключі журавлині,
Знов летять на чужину,
Земляки-українці,
Покидають свій край.
Розкидала їх доля,
Як маленькі зернинки,
Сняться гори їм рідні,
І дзвінкий водограй!..

Приспів:
Україно-Матусю,
Чом ти нас не зігріла?
Ми пішли сиротами
У далекі світи...
Адже ми тебе завжди
Так вірно любили,
А тепер хочем щастя
На чужині знайти...

В еміграції вже ми
Розпустили коріння,
І вона уже стала
Для нас всіх дорога.
Нам би тільки сміятись,
Нам би щиро радіти,
Але в серці лишилась
За тобою туга...

Приспів.

Ви летіть в Україну,
Дорогі журавлята,
Там, де верби плакучі,
Що їх бачимо в сні...
Не судилось вернутись
Нам у батьківську хату,
Емігрантами вмремо
Ми в чужій стороні...

Приспів','["pisni.org.ua", "cat:emigration", "Пісні про еміґрацію"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4434333'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4434333','Емігрантська','Мов ключі журавлині,
