INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4433338','Летять журавлі','Музика: Степан Кривенький Слова: Степан Кривенький','uk','ukraine_before_1917',NULL,NULL,'Волинь моя [Ноти]: пісні для нар. хору, вок. ансамблю та солоспіву.','Пісню виконує Народна аматорська чоловіча капела НД "Просвіта" (м. Горохів).','Над краєм моїм летять журавлі,
Летять журавлі назустріч весні!

Приспів:
Летять журавлі!.. Летять журавлі
За море, в далекі краї...
Кру... Кру... Кру...
Кру... Кру... Кру...
За море в далекі краї...

А, може, в дорозі вас стріне біда,
Верніть на Вкраїну, де хвилі Дніпра!

Приспів.

Доріг є багато і скрізь є весна,
Та ви пам''ятайте, що мати одна!

Приспів.','["pisni.org.ua", "cat:emigration", "Пісні про еміґрацію"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4433338'), datetime('now')),datetime('now'));
