INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_443481','Повстанська могила','(Стоїть сумно край дороги). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Ярослав Николович "Коли прокидається лицар"',NULL,'Стоїть сумно край дороги
Повстанська могила,
А над нею верба рясна
Віти похилила.

Нема хреста у голові,
Не цвіте калина,
Не виходить заквітчати
Молода дівчина.

Десь далеко стара мати
Сина виглядає,
Як згадає, що загинув,
Гірко заридає.

Десь далеко чорнобрива
Пісню заспіває
Про повстанця молодого,
Його вже не має.

Пішов милий у повстанці,
Покинув дівчину;
Казав: "Верну, або згину
За вільну Вкраїну!"

Пішов милий, не вернувся,
Пішов та й загинув.
Свою рідну Україну
Навіки покинув.','["pisni.org.ua", "cat:halycki", "Пісні з Галичини"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_443481'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_443481','Повстанська могила','Стоїть сумно край дороги
Повстанська могила,
А над нею верба рясна
Віти похилила.

Нема хреста у голові,
