INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4431838','Козаки','Музика: Юрій Воронюк Слова: Юрій Воронюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Хто найкраще всіх стріляє, скаче на коні,
У боях перемагає й не горить в вогні?
Хто іще не чув у світі про братів Кличків?
Тільки той, хто ще не знає наших козаків!

Приспів:
Козаки! Козаки
Вам на поміч завжди поспішать!
Козаки, козаки -
Наша слава і наша душа!

Хто в спортзалі любить коней, мати й турніки -
Це майбутні чемпіони — наші козаки!
І в навчанні, і в футболі, як у всі роки,
Є також у нашій школі хлопці-козаки!

Приспів.

В кого шана і повага до своїх батьків?
В кого мужність і відвага? - В наших козаків!
Хто ніколи не буває грубим і різким
І дівчат не ображає? — Наші козаки!

Приспів. (2)','["pisni.org.ua", "cat:devoted", "Пісні присвячені окремим особам"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4431838'), datetime('now')),datetime('now'));
