INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4433634','Хороводна','Музика: Аркадій Філіпенко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ой, ялиночко, ялинко,
Гарні в тебе іграшки!
Ой, ялиночко, ялинко,
Сяють золотом гілки!

Приспів:
Туп, туп, каблучок!
Будем веселиться!
На ялиночці сніжок
Блисками іскриться!

Ой, ялиночко, ялинко,
Дід Мороз танцює сам!
Ой, ялиночко, ялинко,
Стільки втіх принесла нам!

Приспів.

Ой, ялиночко, ялинко,
