INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_4433634_l2','pisniua_4433634','YouTube','https://www.youtube.com/watch?v=mwxaR3W3uEc','video',NULL,2);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4435539','Молитва до Марії','Слова: Марія Чайківчанка','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'О, яке твоє прекрасне ім''я?..
З ікони сяєш, немов лілія,
На різних мовах говорить дитя,
Стиха шепочуть уста Марія...

О, Божа мати, Діво Пресвята!
Марія... Марія... Марія...
Ти Всевишнім до неба піднята,
Що народила світу Месію...

Всі шукаємо тебе, як важко!
Віддають віки земний уклін,
Величають ім''я райські пташки,
Кличе до тебе небесний дзвін...

Освіти наш путь, пречиста зоре!
У божій любові захисти!
Прожени всяку біду і горе,
А у молитві наш дух зрости!

Подай нам мирне небо на землі!
У боротьбі здобути волю!
Хай буде хліб, до хліба на столі...
Вкраїнський рід покращить долю!

Ти випроси в Небесного Отця,
Щоб відчути мир, добро, радість!
Сироті, вдові, матері, в старця
Витри сльозу, захисти старість!..','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4435539'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4435539','Молитва до Марії','О, яке твоє прекрасне ім''я?..
З ікони сяєш, немов лілія,
На різних мовах говорить дитя,
Стиха шепочуть уста Марія...

О, Божа мати, Діво Пресвята!
Марія... Марія... Марія...
Ти Всевишнім до неба піднята,
Що народила світу Месію...

Всі шукаємо тебе, як важко!
Віддають віки земний уклін,
Величають ім''я райські пташки,
Кличе до тебе небесний дзвін...

Освіти наш путь, пречиста зоре!
У божій любові захисти!
Прожени всяку біду і горе,
А у молитві наш дух зрости!

Подай нам мирне небо на землі!
У боротьбі здобути волю!
Хай буде хліб, до хліба на столі...
Вкраїнський рід покращить долю!

Ти випроси в Небесного Отця,
Щоб відчути мир, добро, радість!
Сироті, вдові, матері, в старця
Витри сльозу, захисти старість!..');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4425236','Рідні друзі мої','Музика: Володимир Гуменчук Слова: Мирослав Воньо','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Рідні друзі мої, хто без вас я такий?
Тільки крапля в людськім океані.
Кращі всі почуття віддаю залюбки
Радше вам, швидше вам, ніж коханій...
Хоч дарує вона все тепло чарівне
І зірками очей в душу світить,
Та лиш друзі мої зрозуміють мене,
Як ніхто, як ніхто в цьому світі!..

Приспів:
Я без вас, як без рук, ви - душі оберіг,
Я б і жити без вас в цьому світі не зміг!..
Ви - родина моя, рідні друзі мої,
Я без вас, наче той, що живе без сім''ї!..

Наче в зв''язці одній ми йдемо по житті
Так, як в горах ідуть альпіністи.
Часом хоч грішите, ви для мене - святі,
Рідні друзі мої, альтруїсти!

Приспів.','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4425236'), datetime('now')),datetime('now'));
