INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4434236','Ще ніхто його не бачив','Слова: Віра Паронова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ще ніхто його не бачив,
Та у ліжечка дитячі
Він кладе під подушки       |
Подарунки і книжки.         | (2)

Хочу я побачить чудо
І сьогодні спать не буду!
Довго-довго я не спав:      |
Все чекав, чекав, чекав...  | (2)

Починаю вже дрімати...
Миколай зайшов в кімнату,
Він схилився наді мною      |
І лоскоче бородою!..        | (2)

Щось тихесенько шепоче...
Хочу я відкрити очі,
Та не можу, мабуть, сплю... |
Миколая я люблю!            | (2)','["pisni.org.ua", "cat:svyatyy-mykolay", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4434236'), datetime('now')),datetime('now'));
