INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4437389','Швидкі санчата','Музика: Ігор Танчак Слова: Ігор Танчак','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Мчать на саночках із гірки
Непосиди-хлопчаки,
Розбишаки і дражнилки,
І завзяті смільчаки!

Приспів:
Гей, вітерець!  |
Гей, пустунець, |
Нас наздоганяй! |
Гей, морозець!  |
Гей, морозець,  |
Щічки не щипай! | (2)

Шубки й теплі рукавички
Одягла на них зима!
Із хлопчиськами на санках
Забавляється сама!

Приспів.

А сьогодні зняли шубки,
Відложили саночки,
Під ялинкою танцюють
Черевички-каблучки!

Приспів.

Від морозу, снігу, льоду
Межі радості нема!
Це канікули веселі
Всім дарує нам зима!

Приспів.','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4437389'), datetime('now')),datetime('now'));
