INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_4436838_l2','pisniua_4436838','YouTube','https://www.youtube.com/watch?v=pXGYaeXbWcc','video',NULL,2);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4435030','Молитва до Бога','Музика: Ольга Андрощук Слова: Ольга Андрощук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'І знов підіймаю
До синього неба я очі свої,
І тільки в молитві
Знаходжу я втіху на грішній землі...
Коли відчувають
Тягар і каміння на дорозі моїй,
Тоді я знаходжу
Підтримку спасіння
В молитві простій!..

Приспів:
Молитва до Бога,
Як птах білокрилий,
Що в небо зліта!
Молитва до Бога
То крила Надії
І Віра проста!
Молитва до Бога
То сонячний промінь,
На землю роса!
Де моляться двоє,
Там Божа присутність,
Присутність Христа!

Коли я не маю ні сили,
Ні волі і тяжко мені,
Тоді розмовляти спішу я
З Тобою і вдень, і вночі!
Ти, Господи, з неба
Все бачиш і знаєш
Про долю мою і тільки до Тебе
Приходжу і благаю,
За спокій молю!

Приспів.','["pisni.org.ua", "cat:christian", "Пісні на християнську тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4435030'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4435030','Молитва до Бога','І знов підіймаю
