INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4431083','З Днем Учителя!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Журавлі відчувають вже осінь,
Відлітають у теплі краї,
І дощі креслять лінії косі,
І змивають печалі мої...
Як листочки летять побажання,
Осінь тихо іде в кожен клас,
З днем учителя шлемо вітання, |
Дорогі, з днем учителя вас!   | (2)

Перед вами сидять журавлята,
Ще вони не розправили крил,
Ви ж умієте їх окриляти,
І вони набираються сил.
І тоді прилетять побажання,
Із космічних незвіданих трас.
З днем учителя шлемо вітання, |
Дорогі, з днем учителя вас!   | (2)

І наставників ми не забудем,
Хай який нас чекає маршрут!
Нас учили крилатії люди,
Душі їх в наших душах живуть!
І хай сповняться ваші бажання,
І покличе учительський вальс!
З днем учителя шлемо вітання, |
Дорогі, з днем учителя вас!   | (3)','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4431083'), datetime('now')),datetime('now'));
