INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4439032','Різдвяна ніч','Музика: Павло Табаков Слова: Лідія Лазурко. Виконує: Павло Табаков','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'У тиху ніч тут діються дива,
Збуваються забуті вже бажання,
Проходить ніч, у завтра відплива,
Дарує сон чарівний на прощання...
Мов дивний птах, в цю ніч на дах сідає, -
Це ангел Божий небо покидає,
Нам вість несе, і в ній душа співає,
Що світ у серці Бога зустрічає!..

Приспів:
Різдвяна ніч у срібному вбранні
Малює у вікні, мов чарівниця!..
Ми віримо: все бажане здійсниться
В Різдвяну ніч!

Різдвяна ніч у кошику бажань
В твій сон несе, як сонця, помаранчі,
І сяє сонце на долонях вранці,
Різдвяне сонце, сонце з кошика бажань!

Приспів.','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4439032'), datetime('now')),datetime('now'));
