INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4436535','Файна в нас ялиночка','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Піднімайся, весь народ,
Ми заводим хоровод!
Ми заводим хоровод!
Ось тобі моя рука,
Хоровод, немов ріка!
Хоровод, немов ріка!

Приспів:
Файна в нас ялиночка!
На ялинці зірочка,
За віконцем сніг!
Файна в нас ялиночка,
На ялинці зірочка!
Здрастуй, Новий рік!

Веселиться дітвора,
Святкувати вже пора!
Святкувати вже пора!
Подаруночки для всіх,
Значить скоро Новий рік!
Суперсвято - Новий рік!

Приспів.','["pisni.org.ua", "cat:dytyachi", "cat:new-year", "Дитячі пісні", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4436535'), datetime('now')),datetime('now'));
